			SET @rdr_code = dbo.UniqueCode(@rd_rule_desc, @rd_rule_id, 'RDR', @rds_id, @reference_rating_type);
			
		IF dbo.UniqueCodeExists(@rdr_code, @rd_rule_id, 'RDR', @rds_id, @reference_rating_type) = 1
			EXEC dbo.cdosys_Return_UI @proc_id = @@procid,  @throw_error = 1,  @message_code = 'CODE_EXISTS', @s1='Rating Derivation Rule', @s2 = @rdr_code;

		IF dbo.UniqueDescriptionExists(@rd_rule_desc, @rd_rule_id, 'RDR', @rds_id, @reference_rating_type) = 1
			EXEC dbo.cdosys_Return_UI @proc_id = @@procid,  @throw_error = 1,  @message_code = 'DESCRIPTION_EXISTS', @s1='Rating Derivation Rule', @s2 = @rd_rule_desc;
		  

