				@rds_id,
				@rd_rule_desc,
				@rd_rule_type,
				@rd_rule_designation,
				@rd_rule_outlook_pref,
				@rule_priority,
				@reference_rating_type,
				@reference_security_level,
				@reference_rating_agency,
				@reference_issuer_rating_type,
				@rating,
				@ref_rating_min,
				@ref_rating_max,
				@ref_rating_adjustment,
				@ref_rating_adj_min,
				@ref_rating_adj_max,
				@ref_rating_downgrd_adj,
				@ref_rating_upgrade_adj,
