					@m_id_target = @m_id,
					@source_EXP_id = @applicability_rule,
					@target_id = @rd_rule_id,
					@target_type = 'RDAP',
					@entity_id = @entity_id,
					@new_EXP_id = @exp_id_new OUTPUT;
			END

		END
		ELSE
		BEGIN
			UPDATE dbo.RD_Rule
			SET 
				rdr_code = @rdr_code,
				rd_rule_desc = @rd_rule_desc,
				rd_rule_type = @rd_rule_type,
