			IF @prev_rule_priority IS NULL OR @prev_rule_priority <> @rule_priority
			BEGIN
				-- For inserts or moving up (to lower priority number), increment rules at target position
				IF @prev_rule_priority IS NULL OR @rule_priority < @prev_rule_priority
				BEGIN
