					@target_id = @rd_rule_id,
					@target_type = 'RDAP',
					@entity_id = @entity_id,
					@new_EXP_id = @exp_id_new OUTPUT;
			END

		END
		ELSE
		BEGIN
			UPDATE dbo.RD_Rule
			SET 
				rdr_code = @rdr_code,
				rd_rule_desc = @rd_rule_desc,
				rd_rule_type = @rd_rule_type,
				rd_rule_designation = @rd_rule_designation,
				rd_rule_outlook_pref = @rd_rule_outlook_pref,
				rule_priority = @rule_priority,
				reference_rating_type = @reference_rating_type,
				reference_security_level = @reference_security_level,
				reference_rating_agency = @reference_rating_agency,
				reference_issuer_rating_type = @reference_issuer_rating_type,
				rating = @rating,
				ref_rating_min = @ref_rating_min,
				ref_rating_max = @ref_rating_max,
				ref_rating_adjustment = @ref_rating_adjustment,
				ref_rating_adj_min = @ref_rating_adj_min,
				ref_rating_adj_max = @ref_rating_adj_max,
				ref_rating_downgrd_adj = @ref_rating_downgrd_adj,
				ref_rating_upgrade_adj = @ref_rating_upgrade_adj,
				ref_rating_neg_outlook_adj = @ref_rating_neg_outlook_adj,
				ref_rating_pos_outlook_adj = @ref_rating_pos_outlook_adj,
				multiple_rating_calc_method = @multiple_rating_calc_method,
				multiple_rating_rounding_method = @multiple_rating_rounding_method,
				applicability_rule = @applicability_rule,
				rd_rule_comments = @rd_rule_comments
			WHERE 
				rd_rule_id = @rd_rule_id;

		END

		IF @applicability_rule_SQL IS NOT NULL
		BEGIN
			SELECT @delete_exp_id = exp_id from dbo.EXP_Expression where exp_target_key = @rd_rule_id AND exp_target_type = 'RDAP';

		  IF (@delete_exp_id IS NOT NULL)
			 BEGIN
				EXEC dbo.EXP_Expression_del
					@exp_id = @delete_exp_id,
					@exp_target_type = 'RDAP',
					@exp_target_key = @rd_rule_id,
					@user_id = @user_id,
					@operation_confirmed = 1
				END
			IF (@applicability_rule_sql  != '')
			 BEGIN
				EXEC dbo.EXP_Expression_put  
					@m_id = @m_id,
					@exp_sql = @applicability_rule_sql,  
					@entity_id = @entity_id,  
					@target_type = 'RDAP',  
					@exp_target_key = @rd_rule_id,  
					@exp_description = NULL,  
					@user_id = @user_id,  
					@exp_id = @exp_id_new OUTPUT;  
			 END

			UPDATE 	dbo.RD_rule SET applicability_rule = @exp_id_new WHERE  rd_rule_id = @rd_rule_id;
		END;

		/* Clean up the order if sort_rules flag is set */
		IF (@sort_rules = 1)
		BEGIN
			IF @order_max_min IS NULL
				BEGIN
					UPDATE dbo.RD_Rule
					SET rule_priority = rule_priority + 1
					WHERE rds_id = @rds_id AND rule_priority >= @rule_priority AND rd_rule_id <> @rd_rule_id;

					UPDATE dbo.RD_Rule
					SET rule_priority = @rule_priority
					WHERE rds_id = @rds_id AND rd_rule_id = @rd_rule_id;
				END

			IF @order_max_min IS NOT NULL AND @order_max_min = 'MAX'
				BEGIN 
					UPDATE dbo.RD_Rule
					SET rule_priority = rule_priority + 1
					WHERE rds_id = @rds_id AND rule_priority >= @rule_priority AND rd_rule_id <> @rd_rule_id;
					
					UPDATE dbo.RD_Rule
					SET rule_priority = @rule_priority
					WHERE rds_id = @rds_id AND rd_rule_id = @rd_rule_id;
				END
			

			IF @order_max_min IS NOT NULL AND @order_max_min = 'MIN'
				BEGIN
					UPDATE dbo.RD_Rule
					SET rule_priority = rule_priority + 1
					WHERE rds_id = @rds_id AND rule_priority >= @rule_priority AND rd_rule_id <> @rd_rule_id;
					
					UPDATE dbo.RD_Rule
					SET rule_priority = @rule_priority
					WHERE rds_id = @rds_id AND rd_rule_id = @rd_rule_id;
				END

		END

		SELECT
			@pk_id = @rd_rule_id,
			@operation_primary_key = 'rd_rule_id;' + CAST(@rd_rule_id AS varchar) + '|rds_id;' + CAST(@rds_id AS varchar);
			
		--Success--
		EXEC dbo.cdosys_End_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,
			@starting_tran_count = @tran_count,		
			@pk_id = @pk_id, 
			@operation_confirmed = @operation_confirmed,
			@operation_details = @operation_details,
			@operation_primary_key = @operation_primary_key,
			@message_code = @message_code;		

		IF @@trancount > @tran_count
			COMMIT TRANSACTION @proc_name;
		
	END TRY
	BEGIN CATCH 
		
		IF @@trancount > 0
		BEGIN
		
			DECLARE @stack TABLE (stack_type varchar(25) NOT NULL, proc_id int NOT NULL, nest_level int NOT NULL, stack_message nvarchar(4000) NULL, stack_xml XML NULL);

			INSERT INTO @stack (stack_type, proc_id, nest_level, stack_message, stack_xml)
				SELECT stack_type, proc_id, nest_level, stack_message, stack_xml FROM dbo.cdosys_Stack_List(@@procid, @@nestlevel, NULL);
			
			IF XACT_STATE() = -1
				ROLLBACK TRANSACTION;
			ELSE
				ROLLBACK TRANSACTION @proc_name;
		
			INSERT INTO dbo.cdosys_Stack(spid, proc_id, nest_level, stack_type, stack_message, stack_xml)
				SELECT @@spid, proc_id, nest_level, stack_type, stack_message, stack_xml FROM @stack;
		END
		
		EXEC dbo.cdosys_Return_UI @proc_id = @@procid, @pk_id = @pk_id, @operation_primary_key = @operation_primary_key, @starting_tran_count = @tran_count;
				
	END CATCH
END;
GO

