tiple_rating_calc_method char(4),
	@multiple_rating_rounding_method char(4),
	@applicability_rule int = NULL,
	@applicability_rule_sql varchar(MAX) = NULL,
	@rd_rule_comments comments_small = NULL,
	@copy_source_id int = NULL, /* only used for inserts from RD_Rule_copy */
	@sort_rules bit = 0,
	@user_id dbo.user_id,
	@operation_confirmed int = 0,
	@silent_mode tinyint = 0

AS
BEGIN

	SET NOCOUNT ON;
	BEGIN TRY;

		DECLARE
			@proc_name sysname,
			@tran_count int,
			@message_code varchar(50),
			@operation_details varchar(1000),
			@operation_primary_key varchar(1000),
			@pk_id int;

		SELECT 
			@proc_name = object_name(@@procid),
			@tran_count = @@trancount,
			@pk_id = @rd_rule_id,
			@operation_primary_key = NULL; --set below--
			
		
	
		IF @@trancount = 0
			BEGIN TRAN @proc_name;
		ELSE
			SAVE TRAN @proc_name;


		--Start--
		EXEC dbo.cdosys_Start_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,			
			@starting_tran_count = @tran_count,
			@pk_id = @pk_id, 
			@row_version = NULL, 
			@operation_confirmed = @operation_confirmed;


		DECLARE
			@rds_number int, 	
			@rating_agency dbo.lookup_code, 
			@entity_id int,
			@exp_id_new int,
			@delete_exp_id int,
			@order_max_min varchar(25) = 'MAX',
			@old_priority int;

		SELECT @rating = CASE WHEN @reference_rating_type <> 'FIXD' THEN NULL ELSE @rating END;
		SELECT @entity_id = entity_id FROM dbo.RD_Scenario WHERE rds_id = @rds_id;
		SELECT @old_priority = rule_priority FROM dbo.RD_Rule WHERE rd_rule_id = @rd_rule_id;
		SELECT @order_max_min = CASE WHEN @rule_priority > @old_priority THEN 'MIN' ELSE 'MAX' END;

		SELECT
			@rating_agency = rs.rating_agency,
			@rds_number = rs.rds_number
		 FROM 
			dbo.RD_Scenario rs
		 WHERE
			rs.rds_id = @rds_id;

		/* regen code if description changed */
		IF EXISTS (SELECT * FROM dbo.RD_Rule WHERE rd_rule_id = @rd_rule_id AND rd_rule_desc <> @rd_rule_desc)
			SET @rdr_code = 'AUTO_ASSIGN';

		IF ISNULL(@rdr_code,'AUTO_ASSIGN') = 'AUTO_ASSIGN'
			SET @rdr_code = dbo.UniqueCode(@rd_rule_desc, @rd_rule_id, 'RDR', @rds_id, @reference_rating_type);
			
		IF dbo.UniqueCodeExists(@rdr_code, @rd_rule_id, 'RDR', @rds_id, @reference_rating_type) = 1
			EXEC dbo.cdosys_Return_UI @proc_id = @@procid,  @throw_error = 1,  @message_code = 'CODE_EXISTS', @s1='Rating Derivation Rule', @s2 = @rdr_code;

		IF dbo.UniqueDescriptionExists(@rd_rule_desc, @rd_rule_id, 'RDR', @rds_id, @reference_rating_type) = 1
			EXEC dbo.cdosys_Return_UI @proc_id = @@procid,  @throw_error = 1,  @message_code = 'DESCRIPTION_EXISTS', @s1='Rating Derivation Rule', @s2 = @rd_rule_desc;
		  

		IF ISNULL(@rd_rule_id, 0) = 0
		BEGIN

			INSERT dbo.RD_Rule(
				rds_id,
				rd_rule_desc,
				rd_rule_type,
				rd_rule_designation,
				rd_rule_outlook_pref,
				rule_priority,
				reference_rating_type,
				reference_security_level,
				reference_rating_agency,
				reference_issuer_rating_type,
				rating,
				ref_rating_min,
				ref_rating_max,
				ref_rating_adjustment,
				ref_rating_adj_min,
				ref_rating_adj_max,
				ref_rating_downgrd_adj,
				ref_rating_upgrade_adj,
				ref_rating_neg_outlook_adj,
				ref_rating_pos_outlook_adj,
				multiple_rating_calc_method,
				multiple_rating_rounding_method,
				applicability_rule,
				rd_rule_comments,
				entity_id,
				m_id,
				copy_source_id,
				rdr_code)
			VALUES (
				@rds_id,
				@rd_rule_desc,
				@rd_rule_type,
				@rd_rule_designation,
				@rd_rule_outlook_pref,
				@rule_priority,
				@reference_rating_type,
				@reference_security_level,
				@reference_rating_agency,
				@reference_issuer_rating_type,
				@rating,
				@ref_rating_min,
				@ref_rating_max,
				@ref_rating_adjustment,
				@ref_rating_adj_min,
				@ref_rating_adj_max,
				@ref_rating_downgrd_adj,
				@ref_rating_upgrade_adj,
				@ref_rating_neg_outlook_adj,
				@ref_rating_pos_outlook_adj,
				@multiple_rating_calc_method,
				@multiple_rating_rounding_method,
				@exp_id_new,
				@rd_rule_comments,
				@entity_id,
				@m_id,
				@copy_source_id,
				@rdr_code);


			SELECT @rd_rule_id = SCOPE_IDENTITY();
					
			IF @applicability_rule IS NOT NULL
			BEGIN
				EXEC dbo.EXP_copy
					@m_id_target = @m_id,
					@source_EXP_id = @applicability_rule,
					@target_id = @rd_rule_id,
					@target_type = 'RDAP',
					@entity_id = @entity_id,
					@new_EXP_id = @exp_id_new OUTPUT;
			END

		END
		ELSE
		BEGIN
			UPDATE dbo.RD_Rule
			SET 
				rdr_code = @rdr_code,
				rd_rule_desc = @rd_rule_desc,
				rd_rule_type = @rd_rule_type,
				rd_rule_designation = @rd_rule_designation,
				rd_rule_outlook_pref = @rd_rule_outlook_pref,
				rule_priority = @rule_priority,
				reference_rating_type = @reference_rating_type,
				reference_security_level = @reference_security_level,
				reference_rating_agency = @reference_rating_agency,
				reference_issuer_rating_type = @reference_issuer_rating_type,
				rating = @rating,
				ref_rating_min = @ref_rating_min,
				ref_rating_max = @ref_rating_max,
				ref_rating_adjustment = @ref_rating_adjustment,
				ref_rating_adj_min = @ref_rating_adj_min,
				ref_rating_adj_max = @ref_rating_adj_max,
				ref_rating_downgrd_adj = @ref_rating_downgrd_adj,
				ref_rating_upgrade_adj = @ref_rating_upgrade_adj,
				ref_rating_neg_outlook_adj = @ref_rating_neg_outlook_adj,
				ref_rating_pos_outlook_adj = @ref_rating_pos_outlook_adj,
				multiple_rating_calc_method = @multiple_rating_calc_method,
				multiple_rating_rounding_method = @multiple_rating_rounding_method,
				applicability_rule = @applicability_rule,
				rd_rule_comments = @rd_rule_comments
			WHERE 
				rd_rule_id = @rd_rule_id;

		END

		IF @applicability_rule_SQL IS NOT NULL
		BEGIN
			SELECT @delete_exp_id = exp_id from dbo.EXP_Expression where exp_target_key = @rd_rule_id AND exp_target_type = 'RDAP';

		  IF (@delete_exp_id IS NOT NULL)
			 BEGIN
				EXEC dbo.EXP_Expression_del
					@exp_id = @delete_exp_id,
					@exp_target_type = 'RDAP',
					@exp_target_key = @rd_rule_id,
					@user_id = @user_id,
					@operation_confirmed = 1
				END
			IF (@applicability_rule_sql  != '')
			 BEGIN
				EXEC dbo.EXP_Expression_put  
					@m_id = @m_id,
					@exp_sql = @applicability_rule_sql,  
					@entity_id = @entity_id,  
					@target_type = 'RDAP',  
					@exp_target_key = @rd_rule_id,  
					@exp_description = NULL,  
					@user_id = @user_id,  
					@exp_id = @exp_id_new OUTPUT;  
			 END

			UPDATE 	dbo.RD_rule SET applicability_rule = @exp_id_new WHERE  rd_rule_id = @rd_rule_id;
		END;

		/* Clean up the order if sort_rules flag is set */
		IF (@sort_rules = 1)
		BEGIN
			DECLARE @updated_rule_priority int;

			SET @updated_rule_priority = @rule_priority;
			WHILE EXISTS(SELECT TOP 1 FROM dbo.RD_Rule WHERE rule_priority = @updated_rule_priority AND rds_id = @rds_id AND rd_rule_id <> @rd_rule_id)
			    BEGIN
					UPDATE dbo.RD_Rule
					SET rule_priority = rule_priority + 1
					WHERE rds_id = @rds_id
					AND rule_priority = @updated_rule_priority
					AND rd_rule_id <> @rd_rule_id;

					SET @updated_rule_priority = @updated_rule_priority + 1;
				END

			UPDATE dbo.RD_Rule
			SET rule_priority = @rule_priority
			WHERE rds_id = @rds_id
			AND rd_rule_id = @rd_rule_id;
		END

		SELECT
			@pk_id = @rd_rule_id,
			@operation_primary_key = 'rd_rule_id;' + CAST(@rd_rule_id AS varchar) + '|rds_id;' + CAST(@rds_id AS varchar);
			
		--Success--
		EXEC dbo.cdosys_End_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,
			@starting_tran_count = @tran_count,		
			@pk_id = @pk_id, 
			@operation_confirmed = @operation_confirmed,
			@operation_details = @operation_details,
			@operation_primary_key = @operation_primary_key,
			@message_code = @message_code;		

		IF @@trancount > @tran_count
			COMMIT TRANSACTION @proc_name;
		
	END TRY
	BEGIN CATCH 
		
		IF @@trancount > 0
		BEGIN
		
			DECLARE @stack TABLE (stack_type varchar(25) NOT NULL, proc_id int NOT NULL, nest_level int NOT NULL, stack_message nvarchar(4000) NULL, stack_xml XML NULL);

			INSERT INTO @stack (stack_type, proc_id, nest_level, stack_message, stack_xml)
				SELECT stack_type, proc_id, nest_level, stack_message, stack_xml FROM dbo.cdosys_Stack_List(@@procid, @@nestlevel, NULL);
			
			IF XACT_STATE() = -1
				ROLLBACK TRANSACTION;
			ELSE
				ROLLBACK TRANSACTION @proc_name;
		
			INSERT INTO dbo.cdosys_Stack(spid, proc_id, nest_level, stack_type, stack_message, stack_xml)
				SELECT @@spid, proc_id, nest_level, stack_type, stack_message, stack_xml FROM @stack;
		END
		
		EXEC dbo.cdosys_Return_UI @proc_id = @@procid, @pk_id = @pk_id, @operation_primary_key = @operation_primary_key, @starting_tran_count = @tran_count;
				
	END CATCH
END;
