-- <% MACRO\HEADER %>
CREATE PROCEDURE dbo.EXP_Rule_put
/*******************************************************************
* PURPOSE: Adds or updates a rule to the EXP_rule table
* NOTES: 
* AUTHOR: Solomon Roytshteyn
* CREATED: 4/15/2003 
* MODIFIED 
* DATE		AUTHOR			DESCRIPTION
*-------------------------------------------------------------------
*03/06/2019		SC		#58183 Added exp_rule_code
*03/31/2019		SC		#62964 Added logic to make names unique/no special char
*12/22/2023		AS		#392296 Updated for migration
*10/04/2024		SC		#293897 Codes cleanup and unique by model
*12/02/2024     TD		#1536047916	Added logic to call UniqueRuleName differently for create and update rules
*09/29/2025		SC		#308431 Normalize rule names for regex
*******************************************************************/
	@rule_id int = NULL OUTPUT,
	@exp_rule_code varchar(100) = 'AUTO_ASSIGN',
	@rule_name varchar(120),
	@rule_comments comments_big = NULL,
	@rule_description varchar(MAX) = NULL,
	@row_version bigint = NULL,
	@user_id user_id,
	@silent_mode tinyint = 0,
	@operation_confirmed tinyint = 0
AS
BEGIN
	SET NOCOUNT ON;
	BEGIN TRY;

		DECLARE
			@proc_name sysname,
			@tran_count int,
			@message_code varchar(50),
			@operation_details varchar(1000),
			@operation_primary_key varchar(1000),
			@pk_id int;

		SELECT 
			@proc_name = object_name(@@procid),
			@tran_count = @@trancount,
			@pk_id = @rule_id,
			@operation_primary_key = NULL;  --set below--
			
		
		IF @@NESTLEVEL = 1
		OR OBJECT_ID('tempdb..#cdosys_stack') IS NULL
		BEGIN
			DROP TABLE IF EXISTS #cdosys_stack;
			CREATE TABLE #cdosys_Stack(proc_id INT, nest_level INT, stack_type VARCHAR(25), preserve TINYINT DEFAULT(0), stack_message NVARCHAR(4000));
		END;
		
	
		IF dbo.cdosys_ContextInfo_True('NOTRAN') = 0
		BEGIN
			IF @@trancount = 0
				BEGIN TRAN @proc_name;
			ELSE
				SAVE TRAN @proc_name;
		END

		--Start--
		EXEC dbo.cdosys_Start_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,			
			@starting_tran_count = @tran_count,
			@pk_id = @pk_id, 
			@row_version = @row_version, 
			@operation_confirmed = @operation_confirmed;


		IF ISNULL(@rule_id, 0) = 0
		BEGIN
			SET @rule_name = dbo.UniqueRuleName(@rule_name);
		END 
		ELSE
		BEGIN
			-- Since classic allows to update the rule name, make sure the rule name still complies with the
			-- UniqueRuleName logic
			SET @rule_name = dbo.RemoveOrReplaceLeadingDigits(dbo.UniqueCodeClean(REPLACE(REPLACE(REPLACE(dbo.ProperCase(@rule_name), ' ', ''), '_', ''), '-', ''), 0), NULL);
			IF EXISTS (SELECT rule_name FROM dbo.EXP_Rule WHERE rule_id <> @rule_id AND rule_name = @rule_name)
			BEGIN
				SET @rule_name = dbo.UniqueRuleName(@rule_name);
			END
		END

		/* Normalize rule_name so we can use it in regex */
		SET @rule_name = REPLACE(@rule_name, '\', '');
		SET @rule_name = REPLACE(@rule_name, '/', '');
		SET @rule_name = REPLACE(@rule_name, '*', '');
		SET @rule_name = REPLACE(@rule_name, '+', '');
		SET @rule_name = REPLACE(@rule_name, '?', '');
		SET @rule_name = REPLACE(@rule_name, '|', '');


		IF @exp_rule_code = 'AUTO_ASSIGN' --first, create a valid value if we are set to AUTO_ASSIGN--
			SELECT @exp_rule_code = dbo.UniqueCode(@rule_name, NULL, 'EXP_RULE', NULL, NULL);

		IF dbo.UniqueCodeExists(@exp_rule_code, @rule_id, 'EXP_RULE', NULL, NULL) = 1
			EXEC dbo.cdosys_Return_UI @proc_id = @@procid,  @throw_error = 1,  @message_code = 'CODE_EXISTS', @s1='Expression Rule', @s2 = @exp_rule_code;

		DECLARE @RuleDeps TABLE (child_rule_id INT PRIMARY KEY);

		INSERT INTO @RuleDeps(child_rule_id)
 		SELECT rule_id FROM dbo.tf_GetRuleIdsFromExpSql(@rule_description)
  		WHERE rule_id <> @rule_id;

		IF EXISTS (
			WITH CyclicCheck AS
			(
				SELECT d.child_rule_id
				FROM dbo.Exp_Rule_Dependency d
				JOIN @RuleDeps n
					ON d.parent_type = 'R'
					AND d.parent_id = n.child_rule_id

				UNION ALL

				SELECT d.child_rule_id
				FROM dbo.Exp_Rule_Dependency d
				JOIN CyclicCheck c
					ON d.parent_type = 'R'
					AND d.parent_id = c.child_rule_id
			)
			SELECT 1 
			FROM CyclicCheck
			WHERE child_rule_id = @rule_id
		)
			EXEC dbo.cdosys_Return_UI @proc_id = @@procid,  @throw_error = 1,  @message_code = 'Cyclic_Rule_Dependency', @s1='This is a cyclic reference involving rule', @s2 = @exp_rule_code;

		IF ISNULL(@rule_id, 0) = 0
		BEGIN
			INSERT dbo.EXP_Rule (rule_name, rule_comments, exp_rule_code, exp_sql, created_by, create_date, last_updated_by, last_update_date)
				VALUES (@rule_name, @rule_comments, @exp_rule_code, @rule_description, @user_id, CURRENT_TIMESTAMP, @user_id, CURRENT_TIMESTAMP);
	
			SELECT @rule_id = SCOPE_IDENTITY();
		END
		ELSE
		BEGIN
			UPDATE dbo.EXP_Rule
			SET 
				rule_name = @rule_name,
				rule_comments = @rule_comments,
				exp_sql = @rule_description,
				last_updated_by = @user_id,
				last_update_date = CURRENT_TIMESTAMP
			WHERE
				rule_id = @rule_id;
	
		END
		
		DELETE FROM dbo.Exp_Rule_Dependency
  		WHERE parent_type = 'R'
   		AND parent_id = @rule_id;

		INSERT INTO dbo.EXP_Rule_Dependency(parent_type, parent_id, child_rule_id)
  		SELECT 'R',
				@rule_id, 
				child_rule_id
  		FROM @RuleDeps;

		SELECT
			@pk_id = @rule_id,
			@operation_primary_key = 'rule_id;' + CAST(@rule_id AS varchar);


		--Success--
		EXEC dbo.cdosys_End_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,
			@starting_tran_count = @tran_count,		
			@pk_id = @pk_id, 
			@operation_confirmed = @operation_confirmed,
			@operation_details = @operation_details,
			@operation_primary_key = @operation_primary_key,
			@message_code = @message_code;		

		IF @@trancount > @tran_count
			COMMIT TRANSACTION @proc_name;
		
	END TRY
	BEGIN CATCH 
		
		IF @@trancount > 0
		BEGIN
		
			DECLARE @stack TABLE (stack_type varchar(25) NOT NULL, proc_id int NOT NULL, nest_level int NOT NULL, stack_message nvarchar(4000) NULL);

			INSERT INTO @stack (stack_type, proc_id, nest_level, stack_message)
				SELECT stack_type, proc_id, nest_level, stack_message FROM #cdosys_Stack WHERE XACT_STATE() = -1 OR (proc_id = @@PROCID AND nest_level = @@nestlevel);
				 
			IF XACT_STATE() = -1
				ROLLBACK TRANSACTION;
			ELSE IF @@trancount > @tran_count
				ROLLBACK TRANSACTION @proc_name;
		
			INSERT INTO #cdosys_Stack(proc_id, nest_level, stack_type, stack_message)
				SELECT proc_id, nest_level, stack_type, stack_message FROM @stack;
		END
		
		EXEC dbo.cdosys_Return_UI @proc_id = @@procid, @pk_id = @pk_id, @operation_primary_key = @operation_primary_key, @starting_tran_count = @tran_count;
				
	END CATCH
END;
GO

