-- <% MACRO\HEADER %>
CREATE PROCEDURE [dbo].[PS_generate]
/*******************************************************************
* PURPOSE: Generates a new portfolio snapshot from the data stored in the system
* NOTES: 
* CREATED: 10/1/2003 by Michael Reisman, Inga Turgil
* MODIFIED 
* DATE		AUTHOR		DESCRIPTION
*-------------------------------------------------------------------
*03/28/2005	MR	Assumption Scenarios added and processed
*08/05/2005	MR	PS created is always new
*04/19/2006	JS	Added ANSI_WARNINGS OFF
*04/20/2006	JS	Added new multiple as_id parameters
*06/03/2006	SR	Moved projections to the very end of the process
*07/10/2006	JS	Added @ps_purpose.
*07/11/2006	HW	Added Validation logic
*07/11/2006	HW	Added @operation_message_code OUPUT logic
*08/30/2006	HW	Added PS_Item_Rating_update.
*09/20/2006	JS	Added PS_Statistics_generate.
*12/09/2006	SR	Modified statistics
*07/06/2007	JS	Added @operation_result_code validation for summary code at bottom.
*08/14/2007 DM	Modified for sub_entities, referene portfolio and ps scope
*09/28/2007	JS	Added validation for multiple swaps against the same reference portfolio.
*04/07/2007	SR	Modified for new projections
*12/18/2008	JS	Added @ps_compl_cash_basis.
*01/09/2009	CC	Change to calculation sequence.
*04/08/2009	JS	Changed @run_calculations to @ps_run_calc.
*08/03/2009	SC	Added new error handling
*11/04/2009 SC  Added queue processing. bug 963
*04/03/2010	SC	Added more queueing options. bug 971
*06/07/2010	SC	Added ps_status bug 1262
*06/08/2010	SC	Added Read Uncomitted bug 1255
*05/17/2011	SC	Removed call to PS_Actual_Interest_Generate #1820
*08/20/2012	SC	Added call to PS_Version_put for imported snapshots
*11/29/2012	SC	#3478 added call to PS_Portfolio_Hedge_generate
*04/15/2013	SC	#3714 added @dcg_id (assumption scenario)
*03/24/2014	SR	#4682 Added new proj source option
*12/16/2014	SC	#5525 Added entity level custom fields for import snapshots
*09/23/2015	SC	#10853 Added ability to use system projections for notes in imported snapshot
*08/17/2016	SC	#24004 Increased table_string to varchar(max)
*06/05/2017	SC	#36349 Added @no_queue
*06/15/2018	SC	#50616 Added check for limits
*08/29/2018	SC	#54350 Added snapshot isolation
*11/06/2018	SC	#53405 Added @m_id
*02/25/2020	SC	#75627 Added call to PS_Industry_generate
*05/04/2020	SC	#76275 Added deal initial exch rates
*06/04/2020	SC	#75585 Added ps_run_calc
*06/22/2020	TK	#77100. Changed PS_DC_Calculation_Group_run 's param @dcg_id to @dcg_code
*07/22/2020	SC	#76666 PS_Issue redesign
*01/13/2021 SC	#156159 Removing Snapshot Isolation Level
*02/04/2021	SC	#173806 Adding logic to create PS_TR_Summary rows before running tests
*10/25/2021	TK	#195832. #215671. Move Interest Projections generation before generating Issues to assist "Asset Projected Interest Calculator" when using System Data for Projections
*11/28/2022	SC	#260074 Added snap_code
*10/22/2022	SS	#289170. Added source_entities field to dbo.PS_Issue
*08/05/2024	TD	#285195 Updated for migration 
*02/25/2026	AM	#313165 Modified to create #cdosys_Stack temp Table before Calling PS_Generate_debug
*******************************************************************/
(
	@user_id user_id = NULL,
	@ps_id int = NULL OUTPUT,
	@snap_code varchar(100) = 'AUTO_ASSIGN',
	@ps_description varchar(100) = NULL,
	@entity_id int = NULL,
	@sub_entity_id int = NULL,
	@rp_id int = NULL,
	@ps_scope lookup_code = 'AP',
	@as_of_date smalldatetime = NULL,
	@date_basis lookup_code = NULL,
	@ps_purpose lookup_code = 'GU',
	@ps_type lookup_code = NULL,
	@m_id int = NULL,
	@dcg_id_1 int = NULL, /* Assumption Scenario */
	@calc_list varchar(1000) = NULL,
	@comments comments_big = NULL,
	@display_summary tinyint = 0,
	@proj_source lookup_code = 'PS',
	@ps_compl_cash_basis lookup_code = 'PS',
	@ps_run_calc lookup_code = 'PSG',
	@projection_settings varchar(4000) = NULL,
	@silent_mode tinyint = 0,
	@operation_confirmed tinyint = 0,
	@que_id int = NULL,
	@no_queue bit = 0,
	@preload_test_results bit = 1,
	@source_entities varchar(500) = NULL

)
AS
BEGIN

	SET NOCOUNT ON;
	BEGIN TRY;

	DECLARE
		@queue_value varchar(25),
		@existing_ps_count_date_basis int,
		@existing_ps_count_ps_purpose int,
		@existing_ps_count_proj_source int,
		@date_basis_limit int,
		@ps_purpose_limit int,
		@proj_source_limit int,
		@dcs_id int,
		@dcg_code varchar(100),
		@stack_string_op_details nvarchar(4000),
		@dcs_list varchar(1000); /* calc list derived from as_of_date */


	IF @entity_id IS NULL
		SELECT @entity_id = dbo.PS_ModelEntity(@m_id);

	SET @queue_value = ISNULL(dbo.ConfigValue('QUEUE_PS_GEN', NULL),'None');
	
	DECLARE @limits TABLE (config_code varchar(50), config_value varchar(255), ps_limit int);

	--snapshot generate queue
	IF EXISTS (SELECT * FROM dbo.Queue_PS_Generate WHERE que_id = @que_id)
	BEGIN
		SELECT
			@user_id = user_id, 
			@ps_id = ps_id, 
			@snap_code = snap_code,
			@ps_description = ps_description, 
			@entity_id = entity_id, 
			@sub_entity_id = sub_entity_id, 
			@source_entities = source_entities,
			@rp_id = rp_id, 
			@ps_scope = ps_scope, 
			@as_of_date = as_of_date, 
			@date_basis = date_basis, 
			@ps_purpose = ps_purpose, 
			@ps_type = ps_type, 
			@m_id = m_id, 
			@dcg_id_1 = dcg_id_1,
			@calc_list = calc_list, 
			@comments = comments, 
			@display_summary = display_summary, 
			@proj_source = proj_source, 
			@ps_compl_cash_basis = ps_compl_cash_basis, 
			@ps_run_calc = ps_run_calc, 
			@projection_settings = projection_settings, 
			@silent_mode = silent_mode, 
			@operation_confirmed = operation_confirmed
		FROM
			dbo.Queue_PS_Generate
		WHERE
			que_id = @que_id;
	
	END
	ELSE
	BEGIN
		

		BEGIN TRY
		INSERT INTO @limits (config_code, config_value, ps_limit)
			SELECT
				'PS_LIMIT_DATE_BASIS',
				dbo.StringToken(record_string, ';', 1),
				dbo.StringToken(record_string, ';', 2)
			FROM
				dbo.tf_split2(dbo.ConfigValue('PS_LIMIT_DATE_BASIS', @entity_id), '|')
		END TRY
		BEGIN CATCH
		END CATCH

		BEGIN TRY
		INSERT INTO @limits (config_code, config_value, ps_limit)
			SELECT
				'PS_LIMIT_PURPOSE',
				dbo.StringToken(record_string, ';', 1),
				dbo.StringToken(record_string, ';', 2)
			FROM
				dbo.tf_split2(dbo.ConfigValue('PS_LIMIT_PURPOSE', @entity_id), '|')
		END TRY
		BEGIN CATCH
		END CATCH

		BEGIN TRY
		INSERT INTO @limits (config_code, config_value, ps_limit)
			SELECT
				'PS_LIMIT_PROJ_SOURCE',
				dbo.StringToken(record_string, ';', 1),
				dbo.StringToken(record_string, ';', 2)
			FROM
				dbo.tf_split2(dbo.ConfigValue('PS_LIMIT_PROJ_SOURCE', @entity_id), '|')
		END TRY
		BEGIN CATCH
		END CATCH

		SELECT @existing_ps_count_date_basis = COUNT(*) FROM dbo.PS_Portfolio_Snapshot WHERE entity_id = @entity_id AND ps_purpose <> 'MS' AND created_by = @user_id AND ISNULL(@date_basis, 'TRD') = ISNULL(date_basis, 'TRD') AND create_date >= DATEADD(DAY, DATEDIFF(DAY,0, GETDATE()), 0); /* 12:00am this morning */
		SELECT @existing_ps_count_ps_purpose = COUNT(*) FROM dbo.PS_Portfolio_Snapshot WHERE entity_id = @entity_id AND ps_purpose <> 'MS' AND created_by = @user_id AND ISNULL(@ps_purpose, 'GU') = ISNULL(ps_purpose, 'GU') AND create_date >= DATEADD(DAY, DATEDIFF(DAY,0, GETDATE()), 0); 
		SELECT @existing_ps_count_proj_source = COUNT(*) FROM dbo.PS_Portfolio_Snapshot WHERE entity_id = @entity_id AND ps_purpose <> 'MS' AND created_by = @user_id AND ISNULL(@proj_source, 'PS') = ISNULL(proj_source, 'PS') AND create_date >= DATEADD(DAY, DATEDIFF(DAY,0, GETDATE()), 0);


		SELECT @date_basis_limit = ps_limit FROM @limits WHERE config_code = 'PS_LIMIT_DATE_BASIS' AND config_value = ISNULL(@date_basis, 'TRD');
		SELECT @ps_purpose_limit = ps_limit FROM @limits WHERE config_code = 'PS_LIMIT_PURPOSE' AND config_value = ISNULL(@ps_purpose, 'GU');
		SELECT @proj_source_limit = ps_limit FROM @limits WHERE config_code = 'PS_LIMIT_PROJ_SOURCE' AND config_value = ISNULL(@proj_source, 'PS');

		SET @date_basis_limit = ISNULL(@date_basis_limit, 0);
		SET @ps_purpose_limit = ISNULL(@ps_purpose_limit, 0);
		SET @proj_source_limit = ISNULL(@proj_source_limit, 0);

		IF (@date_basis_limit > 0 AND @existing_ps_count_date_basis >= @date_basis_limit)
		OR (@ps_purpose_limit > 0 AND @existing_ps_count_ps_purpose >= @ps_purpose_limit)
		OR (@proj_source_limit > 0 AND @existing_ps_count_proj_source >= @proj_source_limit)
			EXEC dbo.cdosys_Return_UI @proc_id = @@procid,  @throw_error = 1,  @message_code = 'PS_USER_LIMIT', @operation_details = NULL;

		 IF	@que_id IS NULL 
		AND (@queue_value = 'All' OR (@queue_value = 'SD' AND @proj_source IN('SD', 'PSSD')))
		AND @no_queue = 0
		BEGIN
	
			INSERT INTO dbo.Queue_PS_Generate (que_order, [status], [user_id], ps_id, snap_code, ps_description, entity_id, sub_entity_id, source_entities, rp_id, ps_scope, as_of_date, date_basis, ps_purpose, ps_type, m_id, dcg_id_1, calc_list, comments, display_summary, proj_source, ps_compl_cash_basis, ps_run_calc, projection_settings, silent_mode, operation_confirmed)
				SELECT
					ISNULL(MAX(que_order),0) + 1,
					'Waiting',
					@user_id, 
					NULL, 
					@snap_code,
					@ps_description, 
					@entity_id, 
					@sub_entity_id, 
					@source_entities,
					@rp_id, 
					@ps_scope, 
					@as_of_date, 
					@date_basis, 
					@ps_purpose, 
					@ps_type, 
					@m_id,
					@dcg_id_1,
					@calc_list, 
					@comments, 
					@display_summary, 
					@proj_source, 
					@ps_compl_cash_basis, 
					@ps_run_calc, 
					@projection_settings, 
					@silent_mode, 
					@operation_confirmed
				FROM
					dbo.Queue_PS_Generate;
				
			SELECT
				'ps_id;-1' AS [operation_primary_key], *
			FROM 
				dbo.tf_OperationMessage (0, NULL, NULL, '')
			RETURN;	
		END
	END
	

		DECLARE
			@proc_name sysname,
			@tran_count int,
			@save_tran bit = 0,
			@message_code varchar(50),
			@operation_details varchar(1000),
			@operation_primary_key varchar(1000),
			@pk_id int;

		SELECT 
			@proc_name = object_name(@@procid),
			@tran_count = @@trancount,
			@pk_id = @ps_id,
			@operation_primary_key = NULL; --set below--

		IF @@NESTLEVEL = 1
		OR OBJECT_ID('tempdb..#cdosys_stack') IS NULL
		BEGIN
			DROP TABLE IF EXISTS #cdosys_stack;
			CREATE TABLE #cdosys_Stack(proc_id INT, nest_level INT, stack_type VARCHAR(25), preserve TINYINT DEFAULT(0), stack_message NVARCHAR(4000));
		END;

		EXEC dbo.PS_Generate_debug @proc_id = @@procid, @entity_id = @entity_id, @operation = 'ON';			
		
		 IF ISNULL(dbo.ConfigValue('PS_GEN_TRAN', NULL),0) = 1 
		AND dbo.cdosys_ContextInfo_True('NOTRAN') = 0
		BEGIN
			IF @@trancount = 0
				BEGIN TRAN @proc_name;
			ELSE
			BEGIN
				SAVE TRAN @proc_name;
				SET @save_tran = 1;
			END
		END


		--Start--
		EXEC dbo.cdosys_Start_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,			
			@starting_tran_count = @tran_count,
			@pk_id = @pk_id, 
			@row_version = NULL, 
			@operation_confirmed = @operation_confirmed;
			

		/* So we can use indexed schema bound views */
		SET ANSI_WARNINGS ON;

		DECLARE
			@balances_string varchar(1024),
			@psv_id int,
			@table_string varchar(MAX),
			@process_begin_time datetime,
			@system_entity_type lookup_code,
			@dcs_error_message nvarchar(4000),
			@dcs_operation_result_code int,
			@dcs_operation_message_code varchar(50),
			@dcs_action_message_code varchar(50),
			@dcs_operation_details nvarchar(1000);
							
							
		DROP TABLE IF EXISTS #PS_generation_summary;
		
		CREATE TABLE #PS_generation_summary 
		(
			ps_id int,
			exec_order int IDENTITY,
			sp_name varchar(100),
			process_desc varchar(100),
			begin_time datetime,
			end_time datetime,
			process_duration int,
			process_messages varchar(255)
		)

		SELECT @process_begin_time = CURRENT_TIMESTAMP;
		SELECT @system_entity_type = system_entity_type FROM dbo.Entity WHERE entity_id = @entity_id;
		SELECT @ps_scope = ISNULL(@ps_scope, 'AP'); --Force default.--
		SELECT @ps_id = 0; --set ps id to "new"--


		/* Although valid in the asset portfolio, we can't handle multiple swaps pointing
		to the same reference portfolio in a snapshot of asset portfolio scope. */
		IF  @ps_scope = 'AP' 
		AND EXISTS
		(
			SELECT 
				rp_id
			FROM 
				dbo.CDS 
			WHERE 
				entity_id = @entity_id 
			AND rp_id IS NOT NULL 
			AND (@sub_entity_id IS NULL OR sub_entity_id = @sub_entity_id)
			GROUP BY 
				rp_id
			HAVING 
				COUNT(cds_id) > 1
		)
		EXEC dbo.cdosys_Return_UI @proc_id = @@procid,  @throw_error = 1,  @message_code = 'PS_SCOPE_RP_SWAPS', @operation_details = NULL;

		
		--generate portfolio id--
		EXEC dbo.PS_put 
			@ps_id = @ps_id OUTPUT,
			@m_id = @m_id,
			@calc_list = @calc_list,
			@snap_code = @snap_code,
			@ps_description = @ps_description,
			@entity_id = @entity_id,
			@sub_entity_id = @sub_entity_id,
			@rp_id = @rp_id,
			@ps_scope = @ps_scope,
			@as_of_date = @as_of_date,
			@date_basis = @date_basis,
			@ps_purpose = @ps_purpose,
			@ps_type = @ps_type,
			@user_id = @user_id,
			@read_only = 0,
			@as_id_1 = @dcg_id_1,
			@proj_source = @proj_source,
			@ps_compl_cash_basis = @ps_compl_cash_basis,
			@ps_run_calc = @ps_run_calc,
			@preload_test_results = @preload_test_results,
			@comments = @comments,
			@silent_mode = 1;


		IF @que_id IS NOT NULL
			UPDATE dbo.Queue_PS_Generate SET ps_id = @ps_id WHERE que_id = @que_id;

		EXEC dbo.PS_Status_Put @ps_id, @que_id, 'DEAL_DATA';
		EXEC dbo.PS_Deal_Data_generate @ps_id = @ps_id, @run_mode = 'GEN';
		
		EXEC dbo.PS_Status_Put @ps_id, @que_id, 'EX_RT';
		EXEC dbo.PS_Exchange_Rate_generate @ps_id = @ps_id, @deal_data_type = 'CER', @run_mode = 'GEN'; /* spot */
		EXEC dbo.PS_Exchange_Rate_generate @ps_id = @ps_id, @deal_data_type = 'CERI', @run_mode = 'GEN'; /* Initial */


		SET @dcs_id = dbo.DCS_DefaultSequenceId(@m_id);

		SET @dcs_list = dbo.DCS_CalculationStepList(@dcs_id, @as_of_date);
		EXEC dbo.cdosys_Stack_Put @proc_id = @@procid, @nest_level = @@nestlevel, @stack_type = 'DCS_CALC_LIST', @stack_message = @dcs_list;

		IF @ps_type = 'GEN'
		BEGIN 

			
			UPDATE dbo.PS_Portfolio_Snapshot SET m_id = @m_id WHERE ps_id = @ps_id;
				
			EXEC dbo.PS_Status_Put @ps_id, @que_id, 'PORT_BAL';
			EXEC dbo.PS_Balance_generate @ps_id = @ps_id, @silent_mode = 1, @source_entities = @source_entities;
			
			--Interest Projections--
			IF @proj_source IN('SD', 'PSSD') --System Data--
			BEGIN
				EXEC dbo.PS_Status_Put @ps_id, @que_id, 'PROJ';
				EXEC dbo.PS_IPR_generate
					@ps_id = @ps_id,
					@run_mode = 'GEN',
					@projection_settings = @projection_settings;
			END
			
			EXEC dbo.PS_Status_Put @ps_id, @que_id, 'ISSU';
			EXEC dbo.PS_Issue_generate @ps_id = @ps_id, @sub_entity_id = @sub_entity_id, @source_entities = @source_entities;

			EXEC dbo.PS_Status_Put @ps_id, @que_id, 'ITEM';
			EXEC dbo.PS_Item_generate @ps_id = @ps_id, @sub_entity_id = @sub_entity_id;
			
			EXEC dbo.PS_Status_Put @ps_id, @que_id, 'HEDGE';
			EXEC dbo.PS_Portfolio_Hedge_generate @ps_id = @ps_id, @user_id = @user_id;
			EXEC dbo.PS_Hedge_generate @ps_id = @ps_id;
			

			EXEC dbo.PS_Status_Put @ps_id, @que_id, 'ISSU_IND';
			EXEC dbo.PS_Issue_Industry_update @ps_id = @ps_id, @silent_mode = 1;

			EXEC dbo.PS_Status_Put @ps_id, @que_id, 'ISSU_RAT';
			EXEC dbo.PS_Issue_Rating_update @ps_id = @ps_id, @run_mode = 'GEN';
			
			EXEC dbo.PS_Status_Put @ps_id, @que_id, 'ITEM_RAT';
			EXEC dbo.PS_Item_Rating_update @ps_id = @ps_id, @run_mode = 'GEN';
			
			EXEC dbo.PS_Status_Put @ps_id, @que_id, 'CUST';
			EXEC dbo.PS_Custom_Generate @ps_id = @ps_id, @run_mode = 'GEN';


			--generate combo security data--
			IF @system_entity_type = 'CDO'
				EXEC dbo.PS_Combo_generate @ps_id = @ps_id;
			

			--Generate psv record--
			EXEC dbo.PS_Version_put
				@psv_id = @psv_id OUTPUT, 
				@ps_id = @ps_id,
				@preload_test_results = @preload_test_results,
				@user_id = @user_id,
				@silent_mode = 1;
		
			BEGIN TRY
				
				-- Assumption Scenario--
				IF @dcg_id_1 IS NOT NULL
				BEGIN
					SELECT @dcg_code = dcg_code FROM dbo.DC_Calculation_Group WHERE dcg_id = @dcg_id_1
					EXEC dbo.PS_DC_Calculation_Group_run @psv_id = @psv_id, @dcg_code = @dcg_code;
				END
				
				PRINT 'CALC LIST ISSUE 1';

				--Run calculations--
				IF @ps_run_calc = 'PSG' --When Snapshot is Generated--
				BEGIN
					EXEC dbo.PS_Status_Put @ps_id, @que_id, 'CALC';
					EXEC dbo.PS_DCS_run
						@psv_id = @psv_id,
						@dcs_id = @dcs_id,
						@calc_list = @calc_list,
						@run_mode = 'GEN',
						@no_queue = 1, /* only queue calculations when run manually.  If user wants to queue calcs here, they should just queue the whole snapshot */
						@user_id = @user_id,
						@silent_mode = 1;
				END
				PRINT 'CALC LIST ISSUE 2';

			END TRY
			BEGIN CATCH

				SELECT @stack_string_op_details = NULL;
				SELECT
					@stack_string_op_details = STRING_AGG(stack_message, ', ')
				FROM (
					SELECT DISTINCT stack_message FROM #cdosys_Stack WHERE stack_type = 'OPDETAILS' AND stack_message IS NOT NULL) AS s;

				SELECT 
					@dcs_error_message = ERROR_MESSAGE(), 
					@dcs_operation_details = ISNULL(@dcs_operation_details, '') + ISNULL(@stack_string_op_details, '');

				SELECT
					@dcs_operation_result_code = operation_result_code,
					@dcs_operation_message_code = operation_message_code,
					@dcs_action_message_code = action_message_code
				FROM 
					dbo.tf_ActionMessage (@dcs_error_message);
							
			END CATCH
			


		END--@ps_type = 'GEN'--
		ELSE --Just create ps_version record and save dcs_id and calc_list--
		BEGIN


			IF @proj_source = 'PSSD' --System Data For Liabilities--
			BEGIN

				--Interest Projections--
				EXEC dbo.PS_Status_Put @ps_id, @que_id, 'PROJ';
				EXEC dbo.PS_IPR_generate
					@ps_id = @ps_id,
					@run_mode = 'GEN',
					@projection_settings = @projection_settings;
					
				EXEC dbo.PS_Issue_generate @ps_id = @ps_id, @sub_entity_id = NULL;
				EXEC dbo.PS_Item_generate @ps_id = @ps_id, @sub_entity_id = NULL;
				
				--remove assets, leave liabilities--
				DELETE FROM dbo.PS_Item WHERE ps_id = @ps_id AND ps_issue_id in (SELECT ps_issue_id FROM dbo.PS_Issue WHERE ps_id = @ps_id AND ISNULL(issue_category, 'A') = 'A');
				DELETE FROM dbo.PS_Issue_Rating WHERE ps_issue_id in (SELECT ps_issue_id FROM dbo.PS_Issue WHERE ps_id = @ps_id AND ISNULL(issue_category, 'A') = 'A');
				DELETE FROM dbo.PS_Issue WHERE ps_id = @ps_id AND ISNULL(issue_category, 'A') = 'A';

			END

			EXEC dbo.PS_Version_put
				@psv_id = @psv_id OUTPUT, 
				@ps_id = @ps_id,	
				@preload_test_results = @preload_test_results,
				@user_id = @user_id,
				@silent_mode = 1;
							
			UPDATE 
				dbo.PS_Portfolio_Snapshot
			SET 
				m_id = @m_id,
				calc_list = ISNULL(@calc_list, dbo.DCS_CalculationStepList(@dcs_id, @as_of_date))
			WHERE 
				ps_id = @ps_id;

			EXEC dbo.PS_Custom_Generate @ps_id = @ps_id, @run_mode = 'GEN';

		END

		--Calculate statistics and summary--
		EXEC dbo.PS_Statistics_generate @ps_id = @ps_id;
		EXEC dbo.PS_Generation_summary_put
			@sp_name = 'PS_Statistics_generate',
			@process_desc = 'Generate Statistics';
			


		UPDATE #PS_generation_summary
		SET begin_time = ISNULL((SELECT TOP 1 end_time FROM #PS_generation_summary WHERE exec_order < gs.exec_order ORDER BY exec_order DESC), @process_begin_time)
		FROM #PS_generation_summary gs
		WHERE begin_time IS NULL;

		INSERT #PS_generation_summary (sp_name, process_desc, begin_time, end_time, process_messages)
			VALUES ('PS_generate', NULL, @process_begin_time, CURRENT_TIMESTAMP, NULL);

		UPDATE 
			#PS_generation_summary
		SET
			ps_id = @ps_id,
			process_duration = DATEDIFF(ms, begin_time, end_time);

		SET @table_string = '';

		SELECT @table_string 
			= @table_string 
			+ CONVERT(varchar(5), exec_order) + ';'
			+ ISNULL(sp_name, '') + ';' 
			+ ISNULL(process_desc, '') + ';' 
			+ ISNULL(CONVERT(varchar(25), begin_time, 109), '') + ';' 
			+ ISNULL(CONVERT(varchar(25), end_time, 109), '') + ';' 
			+ ISNULL(CONVERT(varchar(10), process_duration), '') + ';' 
			+ ISNULL(process_messages, '') + '|'
		FROM
			#PS_generation_summary;


		--Save generation summary to PS_Statistic.--
		INSERT INTO dbo.PS_Statistic (ps_id, ps_stat_code, ps_stat_value) 
			VALUES (@ps_id, 'GENSUM', @table_string)


		SELECT
			@pk_id = @ps_id,
			@operation_primary_key = 'ps_id;' + CAST(@ps_id AS varchar);
			
		IF @display_summary = 1
		BEGIN
			SELECT * FROM #PS_generation_summary
			SET @silent_mode = 1; --suppress result from cdosys_End_Procedure--
		END
		
		EXEC dbo.PS_Status_Put @ps_id, @que_id, 'FIN';
				
		IF @dcs_error_message IS NOT NULL
			EXEC dbo.cdosys_Return_UI @proc_id = @@procid,  @throw_error = 1,  @message_code = @dcs_error_message, @operation_details = @dcs_operation_details;
		

					
		--Success--
		EXEC dbo.cdosys_End_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,
			@starting_tran_count = @tran_count,		
			@pk_id = @pk_id, 
			@operation_confirmed = @operation_confirmed,
			@operation_details = @operation_details,
			@operation_primary_key = @operation_primary_key,
			@message_code = @message_code;		

		IF @@trancount > @tran_count
			COMMIT TRANSACTION @proc_name;
		
	END TRY
	BEGIN CATCH 
		
		IF @@trancount > 0
		BEGIN
		
			DECLARE @stack TABLE (stack_type varchar(25) NOT NULL, proc_id int NOT NULL, nest_level int NOT NULL, stack_message nvarchar(4000) NULL);

			INSERT INTO @stack (stack_type, proc_id, nest_level, stack_message)
				SELECT stack_type, proc_id, nest_level, stack_message FROM #cdosys_Stack WHERE XACT_STATE() = -1 OR nest_level >= @@nestlevel;			
			
			IF XACT_STATE() = -1
				ROLLBACK TRANSACTION;
			ELSE IF @@trancount > @tran_count OR @save_tran = 1
				ROLLBACK TRANSACTION @proc_name;
		
			INSERT INTO #cdosys_Stack(proc_id, nest_level, stack_type, stack_message)
				SELECT proc_id, nest_level, stack_type, stack_message FROM @stack;
		END
		EXEC dbo.PS_Generate_debug @proc_id = @@procid,  @psv_id = @psv_id, @operation = 'OFFS';
		EXEC dbo.cdosys_Return_UI @proc_id = @@procid, @pk_id = @pk_id, @operation_primary_key = @operation_primary_key, @starting_tran_count = @tran_count;
				
	END CATCH
	EXEC dbo.PS_Generate_debug @proc_id = @@procid,  @psv_id = @psv_id, @operation = 'OFFS';
END;
GO

