CREATE PROCEDURE [dbo].[PS_DCS_run]
/*******************************************************************
* PURPOSE: Prepare to run calcuation sequence
* NOTES: 
* CREATED: 01/06/2009 Charles Chen
* MODIFIED 
* DATE		AUTHOR	DESCRIPTION
*-------------------------------------------------------------------
*05/26/2009	JS	Fixed for when ps_id not passed in.
*08/03/2009	SC	Added new error handling
*02/12/2015	SC	#6754 Added SET ARITHABORT ON;
*06/18/2015	SC	#8933 Run calcs for trading scenario when running
*08/29/2018	SC	#54350 Added snapshot isolation
*11/06/2018	SC	#53405 Added logic for models
*01/13/2021 SC	#156159 Removing Snapshot Isolation Level
*08/15/2022	TK	#218919. #253384. Delete orphaned aggregrate variables when Calculation Block is deleted (and Calculations are re-run)
*07/10/2023	SC	#390936 Performance fix
*08/14/2023	SC	#164526 Added Queueing
*10/04/2024	SC	#293897 Codes cleanup and unique by model
*02/25/2026	AM	#313165 Modified to create #cdosys_Stack temp Table before Calling PS_Generate_debug
*******************************************************************/
(
	@psv_id int = NULL,
	@ps_id int = NULL,
	@ts_id int = NULL,
	@dcs_id int = NULL,
	@calc_list varchar(1000) = NULL OUTPUT,
	@run_mode lookup_code = NULL,  /*GEN:  Run from PS_genarate*/
							/*TEST: Run from Compliance test*/
							/*CALC: Run from Caculation tab*/
							/*TOOL: Run from Tool tab? Need to talk to Solomon*/
	@que_id int = NULL,
	@no_queue bit = 0,
	@user_id user_id = NULL,
	@silent_mode int = 1,
	@operation_confirmed tinyint = 1
)
AS
BEGIN


	SET NOCOUNT ON;
	SET ARITHABORT ON;

	/* So we can use indexed schema bound views */
	SET ANSI_WARNINGS ON;

	BEGIN TRY;

		DECLARE
			@proc_name sysname,
			@tran_count int,
			@save_tran bit = 0,
			@message_code varchar(50),
			@operation_details varchar(1000),
			@operation_primary_key varchar(1000),
			@pk_id int;

		SELECT 
			@proc_name = object_name(@@procid),
			@tran_count = @@trancount,
			@pk_id = @ps_id,
			@operation_primary_key = 'ps_id;' + CAST(@ps_id AS varchar);
		
		IF @@NESTLEVEL = 1
		OR OBJECT_ID('tempdb..#cdosys_stack') IS NULL
		BEGIN
			DROP TABLE IF EXISTS #cdosys_stack;
			CREATE TABLE #cdosys_Stack(proc_id INT, nest_level INT, stack_type VARCHAR(25), preserve TINYINT DEFAULT(0), stack_message NVARCHAR(4000));
		END;
		
		EXEC dbo.PS_Generate_debug @proc_id = @@procid,@psv_id = @psv_id, @operation = 'ON';

		 IF ISNULL(dbo.ConfigValue('PS_GEN_TRAN', NULL),0) = 1 
		AND dbo.cdosys_ContextInfo_True('NOTRAN') = 0
		BEGIN
			IF @@trancount = 0
				BEGIN TRAN @proc_name;
			ELSE
			BEGIN
				SAVE TRAN @proc_name;
				SET @save_tran = 1;
			END
		END


		DECLARE @context_info VARBINARY(128);
		SET @context_info = dbo.cdosys_AddContextInfo('NO_PROC_LOG');
		SET CONTEXT_INFO @context_info;

		--Start--
		EXEC dbo.cdosys_Start_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,			
			@starting_tran_count = @tran_count,
			@pk_id = @pk_id, 
			@row_version = NULL, 
			@operation_confirmed = @operation_confirmed;

		DECLARE
			@entity_id int,
			@as_of_date datetime,
			@calc_run tinyint,  --@calc_run for @ps_id and @ts_id--
			@calc_run_actual tinyint, --@calc_run for actuall portfolio without ts_id--
			@calc_list_output varchar(max),
			@queue_value varchar(25),
			@test_option varchar(4),
			@m_id int,
			@dcs_list VARCHAR(1000); --calc list derived from as of date--

		DECLARE @calc_field TABLE (field_id int, dcb_id int NULL);
		

		IF EXISTS (SELECT * FROM dbo.Queue_PS_Calculations WHERE que_id = @que_id)
		BEGIN
			SELECT
				@user_id = user_id, 
				@psv_id = psv_id, 
				@run_mode = run_mode,
				@calc_list = calc_list,
				@silent_mode = silent_mode, 
				@operation_confirmed = operation_confirmed
			FROM
				dbo.Queue_PS_Calculations
			WHERE
				que_id = @que_id;
		
		END

		IF @psv_id IS NULL
			SELECT @psv_id = psv_id FROM dbo.PS_Version WHERE ps_id = @ps_id AND ISNULL(@ts_id, -1) = ISNULL(ts_id, -1);

		--Get @ps_id and @ts_id if @psv_id is provided--
		SELECT 
			@ps_id = ps_id,
			@ts_id = ts_id,
			@calc_run = calc_run
		FROM 
			dbo.PS_Version
		WHERE 
			psv_id = @psv_id;
		
		SELECT @calc_run_actual = calc_run FROM dbo.PS_Version WHERE ps_id = @ps_id AND ts_id IS NULL;

		--Initialize--
		SELECT 
			@as_of_date = as_of_date,
			@entity_id = entity_id,
			@test_option = '0',
			@m_id = m_id
		FROM 
			dbo.PS_Portfolio_Snapshot 
		WHERE 
			ps_id = @ps_id;

		IF @m_id IS NULL
			SET @m_id = dbo.PS_ModelLatest(@entity_id);

		--Use default sequence if @dcs_id is not provided--
		SELECT @dcs_id = ISNULL(@dcs_id, dbo.DCS_DefaultSequenceId(@m_id));
		
		SELECT @dcs_list = NULL;
		SELECT @dcs_list = stack_message FROM #cdosys_stack WHERE stack_type = 'DCS_CALC_LIST';
		IF @@nestlevel = 1 OR @dcs_list IS NULL
		BEGIN
			SET @dcs_list = dbo.DCS_CalculationStepList(@dcs_id, @as_of_date);
			EXEC dbo.cdosys_Stack_Put @proc_id = @@procid, @nest_level = @@nestlevel, @stack_type = 'DCS_CALC_LIST', @stack_message = @dcs_list;
		END

		SELECT @queue_value = ISNULL(dbo.ConfigValue('QUEUE_PS_CALCS', @entity_id),0);
		
		IF @no_queue = 1
			SET @queue_value = 0;

		IF @que_id IS NULL AND @queue_value = 1
		BEGIN

			IF NULLIF(@calc_list, '') IS NULL
			BEGIN
			
				SELECT @calc_list = calc_list FROM dbo.PS_Portfolio_Snapshot WHERE ps_id = @ps_id;

				IF ISNULL(@calc_list, '') = '' 
					SET @calc_list = @dcs_list;

			END

			IF NULLIF(@calc_list, '') IS NOT NULL
			BEGIN
				IF EXISTS (SELECT * FROM dbo.Queue_PS_Calculations WHERE psv_id = @psv_id AND [status] IN ('Waiting', 'Paused', 'Running'))
					EXEC dbo.cdosys_Return_UI @proc_id = @@procid,  @throw_error = 1,  @message_code = 'PS_CALC_EXISTS', @operation_details = @operation_details;

				INSERT INTO dbo.Queue_PS_Calculations (que_order, [status], [user_id], psv_id, run_mode, calc_list, silent_mode, operation_confirmed)
					SELECT
						ISNULL(MAX(que_order),0) + 1,
						'Waiting',
						@user_id, 
						@psv_id, 
						@run_mode,
						@calc_list,
						@silent_mode, 
						@operation_confirmed
					FROM
						dbo.Queue_PS_Calculations;

			END
			RETURN;	
		END


		--Build default sequence if none exist--
		IF  @dcs_id IS NULL
		AND @run_mode IN ('GEN')
			EXEC dbo.DC_Calculation_Sequence_build
				@m_id = @m_id,
				@dcs_id = @dcs_id OUTPUT, 
				@entity_id = @entity_id,	
				@user_id = @user_id,
				@operation_confirmed = @operation_confirmed,
				@silent_mode = 1;


		--Create/Update PS_Version: Don't do anything if @run_mode = 'TEST' and calculation has been run already--
		IF @psv_id IS NULL
		OR (@calc_run = 1 AND @run_mode <> 'TEST')
			EXEC dbo.PS_Version_put
				@psv_id = @psv_id OUTPUT, 
				@ps_id = @ps_id,	
				@ts_id = @ts_id,
				@calc_run = 0,  
				@user_id = @user_id,
				@operation_confirmed = @operation_confirmed,
				@silent_mode = 1;

		--Initialize final calc_list--
		SELECT @calc_list_output = ISNULL(@calc_list, calc_list) FROM dbo.PS_Portfolio_Snapshot WHERE ps_id = @ps_id;


		--Get calc_list if from dcs_id if none is supplied--
		IF ISNULL(@calc_list_output, '') = '' 
			SET @calc_list_output = @dcs_list;


		--Run calculation: Don't run if @run_mode = 'TEST' and calculation has been run already--
		IF NOT (@run_mode = 'TEST' AND @calc_run = 1)
		BEGIN
			EXEC dbo.PS_Calculations_run
				@psv_id = @psv_id, 
				@calc_list = @calc_list_output,
				@que_id = @que_id,
				@user_id = @user_id,
				@operation_confirmed = @operation_confirmed,
				@silent_mode = 1;
			
			--always run calculations twice as there can be circular dependencies in expressions, rules, etc--
			--remove this for now due to the performance hit.  if users need to run calcs a second time they--
			--can do so manually--
			--EXEC dbo.PS_Calculations_run
			--	@psv_id = @psv_id, 
			--	@calc_list = @calc_list_output,  
			--	@user_id = @user_id,
			--	@operation_confirmed = @operation_confirmed,
			--	@silent_mode = 1;				

			--Delete orphaned aggregrate variables (displayed on Snapshot Aggregate tab)-- 
			--when Calculation Block is deleted after Snapshot is generated and Calculations are re-run--
			IF @calc_run = 1
			BEGIN
				INSERT @calc_field (field_id, dcb_id)
				SELECT DISTINCT
					f.field_id,
					dp.dcb_id
				FROM 
					dbo.DC_CB_Parameter_SB_view dp WITH(NOEXPAND)
					INNER JOIN dbo.cdobiz_Data_Dict dd ON (dd.field_name = LTRIM(RTRIM(dp.param_value)) OR dd.field_name = LTRIM(RTRIM(dp.param_value_ref)))
					INNER JOIN dbo.PS_Aggregate f ON f.field_id = dd.field_id
				WHERE 
					f.psv_id = @psv_id
				AND dp.value_type IN ('F', 'V', 'T', 'B')
				AND dp.entity_id = @entity_id
				AND dp.m_id = @m_id
				AND	(
						EXISTS 
						(	SELECT * 
							FROM 
								dbo.DC_Calculation_Sequence_Step t
								INNER JOIN dbo.DC_Calculation_Sequence s ON t.dcs_id = s.dcs_id
							WHERE 
								t.entity_id = @entity_id
							AND t.m_id = @m_id
							AND t.dcg_id = dp.dcg_id 
							AND t.dcs_id = @dcs_id
							AND t.calc_type = 'CRG' 
							AND dbo.DCS_Effective(@entity_id, t.dcs_calc_id, @as_of_date) = 1
							AND s.dcs_id = @dcs_id
						)
						OR EXISTS (
							SELECT * 
							FROM
								dbo.DC_Calculation_Group g
							WHERE
								g.entity_id = @entity_id
							AND g.dcg_id = dp.dcg_id
							AND group_type = 'POP'
						)
					);
					
					
				DELETE f1 
				FROM
					dbo.PS_Aggregate f1
					LEFT OUTER JOIN @calc_field cf ON f1.field_id = cf.field_id
				WHERE
					f1.psv_id = @psv_id
				AND cf.dcb_id IS NULL;
			END
		END
		
		--Save calc_list to snapshot table: Only for 'GEN' and 'TEST' and for first run--
		IF @run_mode = 'GEN'
		OR (@run_mode = 'TEST' AND @calc_run_actual = 0)
			UPDATE 
				dbo.PS_Portfolio_Snapshot
			SET 
				calc_list = @calc_list_output,
				dcs_id = @dcs_id
			WHERE 
				ps_id = @ps_id;
		
		SET @calc_list = @calc_list_output;

		--Check for errors in calcuation blocks--
		SELECT @operation_details = NULL;
		SELECT
			@operation_details = LEFT(STRING_AGG(CAST(stack_message AS VARCHAR(MAX)), ', '), 1000)
		FROM (
			SELECT DISTINCT stack_message FROM #cdosys_Stack WHERE stack_type = 'CB_RUN_FAILED' AND stack_message IS NOT NULL) AS s;

		IF ISNULL(@operation_details,'') != ''
			EXEC dbo.cdosys_Return_UI @proc_id = @@procid,  @throw_error = 1,  @message_code = 'ONE_OR_MORE', @s1 = 'calculations failed to run:', @operation_details = @operation_details;
			
			
		--Success--
		EXEC dbo.cdosys_End_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,
			@starting_tran_count = @tran_count,		
			@pk_id = @pk_id, 
			@operation_confirmed = @operation_confirmed,
			@operation_details = @operation_details,
			@operation_primary_key = @operation_primary_key,
			@message_code = @message_code;		

		IF @@trancount > @tran_count
			COMMIT TRANSACTION @proc_name;
		
	END TRY
	BEGIN CATCH 
		
		IF @@trancount > 0
		BEGIN
		
		
			DECLARE @stack TABLE (stack_type varchar(25) NOT NULL, proc_id int NOT NULL, nest_level int NOT NULL, stack_message nvarchar(4000) NULL);

			INSERT INTO @stack (stack_type, proc_id, nest_level, stack_message)
				SELECT stack_type, proc_id, nest_level, stack_message FROM #cdosys_Stack WHERE XACT_STATE() = -1 OR nest_level >= @@nestlevel;			
			
			IF XACT_STATE() = -1
				ROLLBACK TRANSACTION;
			ELSE IF @@trancount > @tran_count OR @save_tran = 1
				ROLLBACK TRANSACTION @proc_name;
		
			INSERT INTO #cdosys_Stack(proc_id, nest_level, stack_type, stack_message)
				SELECT proc_id, nest_level, stack_type, stack_message FROM @stack;
		
		END
		EXEC dbo.cdosys_Return_UI @proc_id = @@procid, @pk_id = @pk_id, @operation_primary_key = @operation_primary_key, @starting_tran_count = @tran_count;
	END CATCH
	EXEC dbo.PS_Generate_debug @proc_id = @@procid, @psv_id = @psv_id, @operation = 'OFFD';	
END;
GO

