-- <% MACRO\HEADER %>
CREATE PROCEDURE [dbo].[PS_put]
/*******************************************************************
* PURPOSE: Adds data to PS_portfolio_snapshot
* NOTES: 
* CREATED: 1/8/2003 by Michael Reisman
* MODIFIED 
* DATE		AUTHOR		DESCRIPTION
*-------------------------------------------------------------------
*07/22/2003	MR	Added standard result set
*07/24/2003	MR	Added read-only stop condition
*03/28/2005	MR 	Assumption Scenarios added
*04/19/2006	JS	Added # to ps_description when blank.
*04/20/2006	JS	Added new multiple as_id parameters.
*07/10/2006	JS	Added @ps_purpose and validation for it.
*07/11/2006	HW	Added Validation logic
*07/11/2006	HW	Added @operation_message_code OUPUT logic
*06/20/2007	JS	Fixed validation for PS_PURPOSE_DUPE.
*08/14/2007 DM	Modified for sub_entities, referene portfolio and ps scope
*08/22/2007	SR	Added version
*04/07/2007	SR	Modified for new projections
*12/18/2008	JS	Added @ps_compl_cash_basis.
*08/03/2009	SC	Added new error handling
*03/29/2013	SC	#3024 Added entity_code
*08/07/2013	SC	#4085 Added period dates
*05/30/2016	SC	#19224 Codes to varchar(100)
*10/02/2016	SC	#26073 Codes/fields to varchar(100)
*06/01/2017	SC	#36349 Added logic for master snapshots
*06/04/2020	SC	#75585 Added ps_run_calc
*02/04/2021	SC	#173806 Adding logic to create PS_TR_Summary rows before running tests
*11/28/2022	SC	#260074 Added snap_code
*10/16/2023	SC	#392296 Updated for migration
*10/04/2024	SC	#293897 Codes cleanup and unique by model
*09/15/2025 JK	#305482 Modified for filter_expression delete
*******************************************************************/

	@ps_id int OUTPUT,
	@snap_code varchar(100) = 'AUTO_ASSIGN',
	@ps_description varchar(100) = NULL,
	@entity_id int = NULL,
	@m_id int = NULL,
	@dcs_id INT = NULL,
	@calc_list VARCHAR(1000) = NULL,
	@sub_entity_id int = NULL,
	@rp_id int = NULL,
	@ps_scope lookup_code = 'AP',
	@as_of_date smalldatetime,
	@date_basis dbo.lookup_code,
	@ps_purpose dbo.lookup_code,
	@ps_type dbo.lookup_code,
	@ps_run_calc dbo.lookup_code = NULL,
	@user_id user_id = NULL,
	@read_only tinyint = 0,
	@as_id_1 int = NULL,
	@as_id_2 int = NULL,
	@as_id_3 int = NULL,
	@as_id_4 int = NULL,
	@proj_source lookup_code = 'PS',
	@ps_compl_cash_basis lookup_code = 'PS',
	@comments comments_big = NULL,
	@filter_expression VARCHAR(MAX) = NULL,
	@preload_test_results bit = 0,
	@operation_confirmed tinyint = 0,
	@silent_mode tinyint = 0


AS
BEGIN

	SET NOCOUNT ON;
	BEGIN TRY;

		DECLARE
			@proc_name sysname,
			@tran_count int,
			@save_tran bit = 0,
			@message_code varchar(50),
			@operation_details varchar(1000),
			@operation_primary_key varchar(1000),
			@pk_id int;

		SELECT 
			@proc_name = object_name(@@procid),
			@tran_count = @@trancount,
			@pk_id = @ps_id,
			@operation_primary_key = NULL; --set below--
			
		
		IF @@NESTLEVEL = 1
		OR OBJECT_ID('tempdb..#cdosys_stack') IS NULL
		BEGIN
			DROP TABLE IF EXISTS #cdosys_stack;
			CREATE TABLE #cdosys_Stack(proc_id INT, nest_level INT, stack_type VARCHAR(25), preserve TINYINT DEFAULT(0), stack_message NVARCHAR(4000));
		END;

		 IF ISNULL(dbo.ConfigValue('PS_GEN_TRAN', NULL),0) = 1 
		AND dbo.cdosys_ContextInfo_True('NOTRAN') = 0
		BEGIN
			IF @@trancount = 0
				BEGIN TRAN @proc_name;
			ELSE
			BEGIN
				SAVE TRAN @proc_name;
				SET @save_tran = 1;
			END
		END


		--Start--
		EXEC dbo.cdosys_Start_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,			
			@starting_tran_count = @tran_count,
			@pk_id = @pk_id, 
			@row_version = NULL, 
			@operation_confirmed = @operation_confirmed;

		DECLARE 
			@entity_code varchar(100),
			@next_distribution_date datetime,
			@current_due_period_begin_date datetime,
			@current_due_period_end_date datetime,
			@prior_due_period_end_date datetime,
			@prior_distribution_date datetime,
			@first_distribution_period tinyint,
			@starting_value varchar(8000),
			@model_code varchar(100),
			@exp_id int;
			
		DECLARE @payment_period_date TABLE (field_name varchar(100), field_value varchar(10));

		IF @entity_id IS NULL
			SELECT @entity_id = dbo.PS_ModelEntity(@m_id);

		IF @dcs_id IS NULL
			SELECT @dcs_id = dbo.DCS_DefaultSequenceId(@m_id);

		SELECT @entity_code = entity_code FROM dbo.Entity WHERE entity_id = @entity_id;
		SET @ps_run_calc = ISNULL(@ps_run_calc, dbo.ConfigValue('PS_RUN_CALCULATIONS', @entity_id));

		--There can only be one master snapshot per as of date
		 IF @ps_purpose = 'MS'
		AND EXISTS (SELECT * FROM dbo.PS_Portfolio_Snapshot WHERE ps_purpose = 'MS' AND as_of_date = @as_of_date AND NULLIF(@ps_id, 0) IS NULL )
			EXEC dbo.cdosys_Return_UI @proc_id = @@procid,  @throw_error = 1,  @message_code = 'ONLY_ONE', @s1 = 'master portfolio snapshot may exist for a given As of Date.', @operation_details = NULL;

		--There can only be one PS with a purpose of "Reporting" for any given combination of As of Date, Date Basis and Deal.--
		IF	@ps_purpose = 'RE' 
		AND EXISTS
		(
			SELECT ps_id
			FROM 
				dbo.PS_Portfolio_Snapshot 
			WHERE 
				entity_id = @entity_id 
			AND as_of_date = @as_of_date 
			AND date_basis = @date_basis 
			AND ps_purpose = @ps_purpose
			AND ps_id <> @ps_id
		)
			EXEC dbo.cdosys_Return_UI @proc_id = @@procid,  @throw_error = 1,  @message_code = 'ONLY_ONE', @s1 = 'portfolio snapshot for reporting purposes may exist for a given date, date basis and entity at a time.', @operation_details = NULL;


		IF @ps_description IS NULL
			SELECT @ps_description 
				= CONVERT(varchar,@as_of_date,107)
				+ ' '
				+ dbo.CodeDesc ('PS_TYPE',@ps_type) 
				+ ' #'
				+ CONVERT(varchar(3), (SELECT COUNT(*) + 1 FROM dbo.PS_Portfolio_Snapshot WHERE entity_id = @entity_id AND as_of_date = @as_of_date)) 
				+ ', '
				+ dbo.CodeDesc ('DATE_BASIS',@date_basis);


		IF @snap_code = 'AUTO_ASSIGN'
		BEGIN
			SELECT @starting_value = dbo.SnapshotCodeStartingValue(@entity_id, @m_id, @as_of_date, @date_basis, @ps_purpose);
			SELECT @snap_code = dbo.UniqueCode(@starting_value, @ps_id, 'SNAP', @m_id, NULL);
		END

		IF dbo.UniqueCodeExists(@snap_code, @ps_id, 'SNAP', @m_id, NULL) = 1
			EXEC dbo.cdosys_Return_UI @proc_id = @@procid,  @throw_error = 1,  @message_code = 'CODE_EXISTS', @s1='Portfolio Snapshot', @s2 = @snap_code;

		IF @calc_list IS NULL
		BEGIN
			SELECT @calc_list = stack_message FROM #cdosys_stack WHERE stack_type = 'DCS_CALC_LIST';
			IF @calc_list IS NULL
				SET @calc_list = dbo.DCS_CalculationStepList(@dcs_id, @as_of_date);
		END

		IF @ps_id = 0
		BEGIN
			
			INSERT dbo.PS_Portfolio_Snapshot
			(
				snap_code,
				ps_description,
				m_id,
				dcs_id,
				calc_list,
				entity_id,
				sub_entity_id,
				rp_id,
				ps_scope,
				as_of_date,
				date_basis,
				ps_purpose,
				ps_run_calc,
				ps_type,
				read_only,
				sys_version,
				as_id_1,
				as_id_2,
				as_id_3,
				as_id_4,
				proj_source,
				ps_compl_cash_basis,
				comments,
				entity_code,
				next_distribution_date,
				current_due_period_begin_date,
				current_due_period_end_date,
				prior_due_period_end_date,
				prior_distribution_date,
				first_distribution_period,
				created_by,
				create_date,
				last_updated_by,
				last_update_date
				)
			VALUES
				(
				@snap_code,
				@ps_description,
				@m_id,
				@dcs_id,
				@calc_list,
				@entity_id,
				@sub_entity_id,
				@rp_id,
				@ps_scope,
				@as_of_date,
				@date_basis,
				@ps_purpose,
				@ps_run_calc,
				@ps_type,
				@read_only,
				dbo.cdosys_Version(),
				@as_id_1,
				@as_id_2,
				@as_id_3,
				@as_id_4,
				@proj_source,
				@ps_compl_cash_basis,
				@comments,
				@entity_code,
				@next_distribution_date,
				@current_due_period_begin_date,
				@current_due_period_end_date,
				@prior_due_period_end_date,
				@prior_distribution_date,
				@first_distribution_period,
				@user_id,
				CURRENT_TIMESTAMP,
				@user_id,
				CURRENT_TIMESTAMP
				)

			SELECT @ps_id = SCOPE_IDENTITY();

		END				
		ELSE
			UPDATE dbo.PS_Portfolio_Snapshot
			SET
				ps_description = @ps_description,
				as_of_date = @as_of_date,
				ps_purpose = @ps_purpose,
				read_only = @read_only,
				as_id_1 = @as_id_1,
				as_id_2 = @as_id_2,
				as_id_3 = @as_id_3,
				as_id_4 = @as_id_4,
				comments = @comments,
				last_updated_by = @user_id, 
				last_update_date = CURRENT_TIMESTAMP
			WHERE
				ps_id = @ps_id;

		IF @filter_expression IS NOT NULL
		BEGIN
			SELECT @exp_id = filter_expression FROM dbo.PS_Portfolio_Snapshot WHERE ps_id = @ps_id;
			DECLARE @new_exp_id int;
			
			IF (@exp_id IS NOT NULL)
				BEGIN
					EXEC dbo.EXP_Expression_del
						@exp_id = @exp_id,
						@exp_target_type = 'PSF',
						@exp_target_key = @ps_id,
						@user_id = @user_id,
						@operation_confirmed =

projection_settings, 
					@silent_mode, 
					@operation_confirmed
				FROM
					dbo.Queue_PS_Generate;
				
			SELECT
				'ps_id;-1' AS [operation_primary_key], *
			FROM 
				dbo.tf_OperationMessage (0, NULL, NULL, '')
			RETURN;	
		END
	END
	

		DECLARE
			@proc_name sysname,
			@tran_count int,
			@save_tran bit = 0,
			@message_code varchar(50),
			@operation_details varchar(1000),
			@operation_primary_key varchar(1000),
			@pk_id int;

		SELECT 
			@proc_name = object_name(@@procid),
			@tran_count = @@trancount,
			@pk_id = @ps_id,
			@operation_primary_key = NULL; --set below--

		IF @@NESTLEVEL = 1
		OR OBJECT_ID('tempdb..#cdosys_stack') IS NULL
		BEGIN
			DROP TABLE IF EXISTS #cdosys_stack;
			CREATE TABLE #cdosys_Stack(proc_id INT, nest_level INT, stack_type VARCHAR(25), preserve TINYINT DEFAULT(0), stack_message NVARCHAR(4000));
		END;

		EXEC dbo.PS_Generate_debug @proc_id = @@procid, @entity_id = @entity_id, @operation = 'ON';			
		
		 IF ISNULL(dbo.ConfigValue('PS_GEN_TRAN', NULL),0) = 1 
		AND dbo.cdosys_ContextInfo_True('NOTRAN') = 0
		BEGIN
			IF @@trancount = 0
				BEGIN TRAN @proc_name;
			ELSE
			BEGIN
				SAVE TRAN @proc_name;
				SET @save_tran = 1;
			END
		END


		--Start--
		EXEC dbo.cdosys_Start_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,			
			@starting_tran_count = @tran_count,
			@pk_id = @pk_id, 
			@row_version = NULL, 
			@operation_confirmed = @operation_confirmed;
			

		/* So we can use indexed schema bound views */
		SET ANSI_WARNINGS ON;

		DECLARE
			@balances_string varchar(1024),
			@psv_id int,
			@table_string varchar(MAX),
			@process_begin_time datetime,
			@system_entity_type lookup_code,
			@dcs_error_message nvarchar(4000),
			@dcs_operation_result_code int,
			@dcs_operation_message_code varchar(50),
			@dcs_action_message_code varchar(50),
			@dcs_operation_details nvarchar(1000);
							
							
		DROP TABLE IF EXISTS #PS_generation_summary;
		
		CREATE TABLE #PS_generation_summary 
		(
			ps_id int,
			exec_order int IDENTITY,
			sp_name varchar(100),
			process_desc varchar(100),
			begin_time datetime,
			end_time datetime,
			process_duration int,
			process_messages varchar(255)
		)

		SELECT @process_begin_time = CURRENT_TIMESTAMP;
		SELECT @system_entity_type = system_entity_type FROM dbo.Entity WHERE entity_id = @entity_id;
		SELECT @ps_scope = ISNULL(@ps_scope, 'AP'); --Force default.--
		SELECT @ps_id = 0; --set ps id to "new"--


		/* Although valid in the asset portfolio, we can't handle multiple swaps pointing
		to the same reference portfolio in a snapshot of asset portfolio scope. */
		IF  @ps_scope = 'AP' 
		AND EXISTS
		(
			SELECT 
				rp_id
			FROM 
				dbo.CDS 
			WHERE 
				entity_id = @entity_id 
			AND rp_id IS NOT NULL 
			AND (@sub_entity_id IS NULL OR sub_entity_id = @sub_entity_id)
			GROUP BY 
				rp_id
			HAVING 
				COUNT(cds_id) > 1
		)
		EXEC dbo.cdosys_Return_UI @proc_id = @@procid,  @throw_error = 1,  @message_code = 'PS_SCOPE_RP_SWAPS', @operation_details = NULL;

		
		--generate portfolio id--
		EXEC dbo.PS_put 
			@ps_id = @ps_id OUTPUT,
			@m_id = @m_id,
			@calc_list = @calc_list,
			@snap_code = @snap_code,
			@ps_description = @ps_description,
			@entity_id = @entity_id,
			@sub_entity_id = @sub_entity_id,
			@rp_id = @rp_id,
			@ps_scope = @ps_scope,
			@as_of_date = @as_of_date,
			@date_basis = @date_basis,
			@ps_purpose = @ps_purpose,
			@ps_type = @ps_type,
			@user_id = @user_id,
			@read_only = 0,
			@as_id_1 = @dcg_id_1,
			@proj_source = @proj_source,
			@ps_compl_cash_basis = @ps_compl_cash_basis,
			@ps_run_calc = @ps_run_calc,
			@preload_test_results = @preload_test_results,
			@comments = @comments,
			@silent_mode = 1;


		IF @que_id IS NOT NULL
			UPDATE dbo.Queue_PS_Generate SET ps_id = @ps_id WHERE que_id = @que_id;

		EXEC dbo.PS_Status_Put @ps_id, @que_id, 'DEAL_DATA';
		EXEC dbo.PS_Deal_Data_generate @ps_id = @ps_id, @run_mode = 'GEN';
		
		EXEC dbo.PS_Status_Put @ps_id, @que_id, 'EX_RT';
		EXEC dbo.PS_Exchange_Rate_generate @ps_id = @ps_id, @deal_data_type = 'CER', @run_mode = 'GEN'; /* spot */
		EXEC dbo.PS_Exchange_Rate_generate @ps_id = @ps_id, @deal_data_type = 'CERI', @run_mode = 'GEN'; /* Initial */


		SET @dcs_id = dbo.DCS_DefaultSequenceId(@m_id);

		SET @dcs_list = dbo.DCS_CalculationStepList(@dcs_id, @as_of_date);
		EXEC dbo.cdosys_Stack_Put @proc_id = @@procid, @nest_level = @@nestlevel, @stack_type = 'DCS_CALC_LIST', @stack_message = @dcs_list;

		IF @ps_type = 'GEN'
		BEGIN 

			
			UPDATE dbo.PS_Portfolio_Snapshot SET m_id = @m_id WHERE ps_id = @ps_id;
				
			EXEC dbo.PS_Status_Put @ps_id, @que_id, 'PORT_BAL';
			EXEC dbo.PS_Balance_generate @ps_id = @ps_id, @silent_mode = 1, @source_entities = @source_entities;
			
			--Interest Projections--
			IF @proj_source IN('SD', 'PSSD') --System Data--
			BEGIN
				EXEC dbo.PS_Status_Put @ps_id, @que_id, 'PROJ';
				EXEC dbo.PS_IPR_generate
					@ps_id = @ps_id,
					@run_mode = 'GEN',
					@projection_settings = @projection_settings;
			END
			
			EXEC dbo.PS_Status_Put @ps_id, @que_id, 'ISSU';
			EXEC dbo.PS_Issue_generate @ps_id = @ps_id, @sub_entity_id = @sub_entity_id, @source_entities = @source_entities;

			EXEC dbo.PS_Status_Put @ps_id, @que_id, 'ITEM';
			EXEC dbo.PS_Item_generate @ps_id = @ps_id, @sub_entity_id = @sub_entity_id;
			
			EXEC dbo.PS_Status_Put @ps_id, @que_id, 'HEDGE';
			EXEC dbo.PS_Portfolio_Hedge_generate @ps_id = @ps_id, @user_id = @user_id;
			EXEC dbo.PS_Hedge_generate @ps_id = @ps_id;
			

			EXEC dbo.PS_Status_Put @ps_id, @que_id, 'ISSU_IND';
			EXEC dbo.PS_Issue_Industry_update @ps_id = @ps_id, @silent_mode = 1;

			EXEC dbo.PS_Status_Put @ps_id, @que_id, 'ISSU_RAT';
			EXEC dbo.PS_Issue_Rating_update @ps_id = @ps_id, @run_mode = 'GEN';
			
			EXEC dbo.PS_Status_Put @ps_id, @que_id, 'ITEM_RAT';
			EXEC dbo.PS_Item_Rating_update @ps_id = @ps_id, @run_mode = 'GEN';
			
			EXEC dbo.PS_Status_Put @ps_id, @que_id, 'CUST';
			EXEC dbo.PS_Custom_Generate @ps_id = @ps_id, @run_mode = 'GEN';


			--generate combo security data--
			IF @system_entity_type = 'CDO'
				EXEC dbo.PS_Combo_generate @ps_id = @ps_id;
			

			--Generate psv record--
			EXEC dbo.PS_Version_put
				@psv_id = @psv_id OUTPUT, 
				@ps_id = @ps_id,
				@preload_test_results = @preload_test_results,
				@user_id = @user_id,
				@silent_mode = 1;
		
			BEGIN TRY
				
				-- Assumption Scenario--
				IF @dcg_id_1 IS NOT NULL
				BEGIN
					SELECT @dcg_code = dcg_code FROM dbo.DC_Calculation_Group WHERE dcg_id = @dcg_id_1
					EXEC dbo.PS_DC_Calculation_Group_run @psv_id = @psv_id, @dcg_code = @dcg_code;
				END
				
				PRINT 'CALC LIST ISSUE 1';

				--Run calculations--
				IF @ps_run_calc = 'PSG' --When Snapshot is Generated--
				BEGIN
					EXEC dbo.PS_Status_Put @ps_id, @que_id, 'CALC';
					EXEC dbo.PS_DCS_run
						@psv_id = @psv_id,
						@dcs_id = @dcs_id,
						@calc_list = @calc_list,
						@run_mode = 'GEN',
						@no_queue = 1, /* only queue calculations when run manually.  If user wants to queue calcs here, they should just queue the whole snapshot */
						@user_id = @user_id,
						@silent_mode = 1;
				END
				PRINT 'CALC LIST ISSUE 2';

			END TRY
			BEGIN CATCH

				SELECT @stack_string_op_details = NULL;
				SELECT
					@stack_string_op_details = STRING_AGG(stack_message, ', ')
				FROM (
					SELECT DISTINCT stack_message FROM #cdosys_Stack WHERE stack_type = 'OPDETAILS' AND stack_message IS NOT NULL) AS s;

				SELECT 
					@dcs_error_message = ERROR_MESSAGE(), 
					@dcs_operation_details = ISNULL(@dcs_operation_details, '') + ISNULL(@stack_string_op_details, '');

				SELECT
					@dcs_operation_result_code = operation_result_code,
					@dcs_operation_message_code = operation_message_code,
					@dcs_action_message_code = action_message_code
				FROM 
					dbo.tf_ActionMessage (@dcs_error_message);
							
			END CATCH
			


		END--@ps_type = 'GEN'--
		ELSE --Just create ps_version record and save dcs_id and calc_list--
		BEGIN


			IF @proj_source = 'PSSD' --System Data For Liabilities--
			BEGIN

				--Interest Projections--
				EXEC dbo.PS_Status_Put @ps_id, @que_id, 'PROJ';
				EXEC dbo.PS_IPR_generate
					@ps_id = @ps_id,
					@run_mode = 'GEN',
					@projection_settings = @projection_settings;
					
				EXEC dbo.PS_Issue_generate @ps_id = @ps_id, @sub_entity_id = NULL;
				EXEC dbo.PS_Item_generate @ps_id = @ps_id, @sub_entity_id = NULL;
				
				--remove assets, leave liabilities--
				DELETE FROM dbo.PS_Item WHERE ps_id = @ps_id AND ps_issue_id in (SELECT ps_issue_id FROM dbo.PS_Issue WHERE ps_id = @ps_id AND ISNULL(issue_category, 'A') = 'A');
				DELETE FROM dbo.PS_Issue_Rating WHERE ps_issue_id in (SELE

projection_settings, 
					@silent_mode, 
					@operation_confirmed
