     {
       dataSource = dataSource.Replace(&quot;@entity_id&quot;, &quot;@entity_id = &quot; + portfolio.Lid);
       dataSource = dataSource.Replace(&quot;@currency_denominated&quot;, &quot;@currency_denominated = &quot; + portfolio.BaseCurrency);
     }
     var sProcDetail = dataSource.Split(&quot;@&quot;).ToList();
     var sProcName = sProcDetail[0];
     sProcDetail.Remove(sProcName);

     var sprocParams = new List&lt;SprocParameter&gt;();
     foreach (var sProc in sProcDetail)
     {
       var parameter = sProc.Split(new char[] { &#39;=&#39; }, StringSplitOptions.RemoveEmptyEntries);
       if (parameter.Length &gt; 1)
       {
         sprocParams.Add(new SprocParameter(parameter[0].Trim(), parameter[1].Trim()));
       }
     }

     var dataSourceList = new Dictionary&lt;string, string&gt;();
     var outParams = await _sprocContext.DynamicSprocCommand(ownerId, sProcName.Trim())
       .WithParameters(sprocParams)
       .WithResultSetAction(record =&gt;
       {
         var key = record.GetValue&lt;string&gt;(code);
         var value = record.GetValue&lt;string&gt;(description);
         if (!string.IsNullOrEmpty(key) &amp;&amp; !string.IsNullOrEmpty(value))
           dataSourceList[key] = value;
       })
       .ExecuteAsync(cancellationToken).ConfigureAwait(false);

     return dataSourceList;
   }

