-- <% MACRO\HEADER %>
CREATE PROCEDURE [dbo].[CCT_Param_put]
/*******************************************************************
* PURPOSE: Adds a Compliance test parameter; re-sorts order and adds to deal_test table if necessary
* NOTES: 
* CREATED: 5/7/2003 Michael Reisman
* MODIFIED 
* DATE		AUTHOR	DESCRIPTION
*-------------------------------------------------------------------
*10/11/2006	SR	Increased size of data_source field 
*11/21/2008	CC	Insert new parameter to dcb paramter table 
*04/27/2009	JS	Added param_type.
*02/08/2010	SC	Added new error handling
*08/03/2013	SC	#4115 Code cleanup
*01/16/2015	SR	#6183 Added template code to facilitate scripting
*08/06/2015	SC	#10026 Added entity_id to DC_Calculation_Block_Parameter
*05/22/2016	SC	#19224 Convert to identity, added param_code
*10/02/2016	SC	#26073 Codes/fields to varchar(100)
*02/28/2019	SC	#58183 Added logic for compliance models
*09/24/2019	TK	#70639. Fixed param value_type passed to dbo.Deal_Test_Param_put & dbo.DC_Calculation_Block_Parameter_put
*06/05/2020	SC	#64097 Re-wrote backfill for performance
*09/23/2024	NP	#Updated for migration
*10/04/2024	SC	#293897 Codes cleanup and unique by model
*07/29/2025	SC	#305462 Added number_output_params
*******************************************************************/
(
	@user_id dbo.user_id,
	@test_param_id int = NULL OUTPUT,
	@test_id int = NULL, /* either id or code must be supplied */
	@template_code varchar(100) = NULL,
	@test_param_name varchar(100),
	@test_param_desc varchar(255),
	@value_type char(1),
	@data_type char(4),
	@code_type char(50) = NULL,
	@param_type dbo.lookup_code = 'INP',
	@test_param_order int,
	@value_required tinyint = 0,
	@data_source varchar(255) = NULL, 
	@data_text_field varchar(30) = NULL, 
	@data_value_field varchar(30) = NULL,
	@ref_test_id int = NULL,
	@SQL_variable_name varchar(128), 
	@SQL_datatype varchar(50) = NULL,
	@lookup_codes varchar(4000) = NULL,
	/* next two are for scripting purposes for new records only */
	@test_param_value varchar(255) = NULL,
	@test_param_value_desc varchar(255) = NULL,
	@silent_mode tinyint = 0,
	@operation_confirmed tinyint = 1,
	@param_code varchar(100) = NULL
)
AS
BEGIN


	SET NOCOUNT ON;
	
	BEGIN TRY;

		DECLARE
			@proc_name sysname,
			@tran_count int,
			@save_tran bit = 0,
			@message_code varchar(50),
			@operation_details varchar(1000),
			@operation_primary_key varchar(1000),
			@pk_id int;

		SELECT 
			@proc_name = object_name(@@procid),
			@tran_count = @@trancount,
			@pk_id = @test_id,
			@operation_primary_key = NULL; --set below--
			
		
		IF @@NESTLEVEL = 1
		OR OBJECT_ID('tempdb..#cdosys_stack') IS NULL
		BEGIN
			DROP TABLE IF EXISTS #cdosys_stack;
			CREATE TABLE #cdosys_Stack(proc_id INT, nest_level INT, stack_type VARCHAR(25), preserve TINYINT DEFAULT(0), stack_message NVARCHAR(4000));
		END;
		
	
		IF dbo.cdosys_ContextInfo_True('NOTRAN') = 0
		BEGIN
			IF @@trancount = 0
				BEGIN TRAN @proc_name;
			ELSE
			BEGIN
				SAVE TRAN @proc_name;
				SET @save_tran = 1;
			END
		END

		--Start--
		EXEC dbo.cdosys_Start_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,			
			@starting_tran_count = @tran_count,
			@pk_id = @pk_id, 
			@row_version = NULL, 
			@operation_confirmed = @operation_confirmed;

		DECLARE 
			@old_param_order int,
			@order_changed int,
			@deal_test_id int,
			@dcb_id int,
			@dcb_param_id int,
			@deal_test_param_id int,
			@m_id int,
			@value_type_derived varchar(50);

		
		SET @param_code = ISNULL(@param_code, UPPER(REPLACE(@SQL_variable_name, '@', '')));
		
		SET @value_type_derived = CASE @param_type WHEN 'INP' THEN 'VAL' WHEN 'OUTP' THEN 'REF' END;

		IF @test_id IS NULL AND @template_code IS NOT NULL
			SELECT @test_id = test_id FROM dbo.CCT WHERE template_code = @template_code; 

		IF ISNULL(@test_param_id, 0) = 0 
			SELECT @test_param_id = cp.test_param_id FROM dbo.CCT_Parameter AS cp WHERE cp.test_id = @test_id AND cp.SQL_variable_name = @SQL_variable_name;

		IF ISNULL(@test_param_id, 0) = 0
		BEGIN

			--re-arrange order of existing parameters if parameter is inserted--
			UPDATE dbo.CCT_Parameter
			SET
				test_param_order = test_param_order + 1
			WHERE 
				test_param_order >= @test_param_order 
			AND test_id = @test_id;

			INSERT dbo.CCT_Parameter (
				test_id,
				test_param_name,
				test_param_desc,
				param_code,
				value_type,
				data_type,
				code_type,
				param_type,
				test_param_order,
				value_required,
				data_source,
				data_text_field,
				data_value_field,
				ref_test_id,
				SQL_variable_name, 
				SQL_datatype,
				lookup_codes,
				test_param_value,
				test_param_value_desc
			)
			VALUES(
				@test_id,
				@test_param_name,
				@test_param_desc,
				@param_code,
				@value_type,
				@data_type,
				@code_type,
				@param_type,
				@test_param_order,
				@value_required,
				@data_source, 
				@data_text_field, 
				@data_value_field,
				@ref_test_id,
				@SQL_variable_name, 
				@SQL_datatype,
				@lookup_codes,
				@test_param_value,
				@test_param_value_desc
			);
			SELECT @test_param_id = SCOPE_IDENTITY();

	
			--If new parameter for existing test, update deal test records--
			INSERT INTO dbo.Deal_Test_Parameter (deal_test_id, entity_id, m_id, test_param_id, value_type, test_param_value, test_param_value_desc, test_param_value_ref, comments, copy_source_id, dtp_code, last_update_date, last_updated_by)
				SELECT
					t.deal_test_id,
					t.entity_id,
					t.m_id,
					@test_param_id,
					@value_type_derived,
					@test_param_value,
					@test_param_value_desc,
					param_value_ref = NULL,
					dbp_comments = NULL,
					copy_source_id = NULL,
					dtp_code = CAST(NEWID() AS varchar(50)),
					last_update_date = GETDATE(),
					last_updated_by = SUBSTRING(@user_id + '_UPDATE_dtp_code', 0, 50) 
				FROM
					dbo.Deal_Test t
				WHERE
					test_id = @test_id;


			UPDATE p
			SET 
				dtp_code = dbo.UniqueCodeClean(UPPER(SUBSTRING(REPLACE(test_name, ' ', '_'), 1, 25) + '_' + SUBSTRING(REPLACE(c.test_param_name, ' ', '_'), 1, 40)),1) + '_' + CAST(p.deal_test_param_id AS VARCHAR),
				last_updated_by = @user_id
			FROM 
				dbo.Deal_Test t
				INNER JOIN dbo.Deal_Test_Parameter p ON t.deal_test_id = p.deal_test_id
				INNER JOIN dbo.CCT_Parameter c ON p.test_param_id = c.test_param_id
			WHERE 
				t.test_id = @test_id
			AND p.last_updated_by = SUBSTRING(@user_id + '_UPDATE_dtp_code', 0, 50);

			--If new parameter for existing calculation, update dcb records--
			INSERT INTO dbo.DC_Calculation_Block_Parameter (dcb_id, entity_id, m_id, param_id, value_type, param_value, param_value_desc, param_value_ref, dbp_comments, copy_source_id, dcbp_code, create_date, created_by, last_update_date, last_updated_by)
				SELECT
					b.dcb_id,
					b.entity_id,
					b.m_id,
					@test_param_id,
					@value_type_derived,
					@test_param_value,
					@test_param_value_desc,
					param_value_ref = NULL,
					dbp_comments = NULL,
					copy_source_id = NULL,
					dcbp_code = CAST(NEWID() AS varchar(50)),
					create_date = GETDATE(),
					created_by = @user_id,
					last_update_date = GETDATE(),
					last_updated_by = SUBSTRING(@user_id + '_UPDATE_dcbp_code', 0, 50)
				FROM
					dbo.DC_Calculation_Block b
				WHERE
					calc_id = @test_id;

			UPDATE p
			SET 
				dcbp_code = dbo.UniqueCodeClean(UPPER(SUBSTRING(REPLACE(dcb_description, ' ', '_'), 1, 25) + '_' + SUBSTRING(REPLACE(c.test_param_name, ' ', '_'), 1, 40)),1) + '_' + CAST(p.dcb_param_id AS VARCHAR),
				last_updated_by = @user_id
			FROM 
				dbo.DC_Calculation_Block b
				INNER JOIN dbo.DC_Calculation_Block_Parameter p ON b.dcb_id = p.dcb_id
				INNER JOIN dbo.CCT_Parameter c ON p.param_id = c.test_param_id
			WHERE 
				b.calc_id = @test_id
			AND p.last_updated_by = SUBSTRING(@user_id + '_UPDATE_dcbp_code', 0, 50)

		END --@test_param_id = 0--
		ELSE --Existing parameter--
		BEGIN
		
			--determine if order has changed and in which direction--
			SELECT @old_param_order = test_param_order FROM dbo.CCT_Parameter WHERE test_param_id = @test_param_id;

			SELECT @order_changed = 
				CASE
					WHEN @old_param_order = @test_param_order THEN 0
					WHEN @old_param_order > @test_param_order THEN 1
					ELSE -1
				END ;

			UPDATE dbo.CCT_Parameter
			SET 
				test_param_name = @test_param_name,
				test_param_desc = @test_param_desc,
				param_code = @param_code,
				value_type = @value_type,
				data_type = @data_type,
				code_type = @code_type,
				param_type = @param_type,
				test_param_order = @test_param_order,
				value_required = @value_required,
				test_param_value = NULL,
				data_source = @data_source, 
				data_text_field = @data_text_field, 
				data_value_field = @data_value_field,
				ref_test_id = @ref_test_id,
				SQL_variable_name = @SQL_variable_name, 
				SQL_datatype = @SQL_datatype,
				lookup_codes = @lookup_codes
			WHERE
				test_param_id = @test_param_id;


			--re-arrange order of existing parameters if parameter's order has changed--
			IF @order_changed = 1 --order decreased - shift order of all parameters above up--
				UPDATE dbo.CCT_Parameter
				SET
					test_param_order = test_param_order + 1
				WHERE 
					test_param_order BETWEEN @test_param_order AND @old_param_order
				AND test_param_id <> @test_param_id
				AND test_id = @test_id;


			IF @order_changed = -1 --order increased - shift order of all parameters below down--
				UPDATE dbo.CCT_Parameter
				SET
					test_param_order = test_param_order - 1
				WHERE 
					test_param_order BETWEEN @old_param_order AND @test_param_order
				AND test_param_id <> @test_param_id
				AND test_id = @test_id;

		END --Existing parameter--

		--clean up the order--
		DECLARE @reorder TABLE (new_order INT NOT NULL PRIMARY KEY CLUSTERED IDENTITY(1,1), test_param_id INT NOT NULL);
		INSERT INTO @reorder (test_param_id)
			SELECT test_param_id FROM dbo.CCT_Parameter WHERE test_id = @test_id ORDER BY test_param_order;
			
		UPDATE cct
		SET cct.test_param_order = r.new_order
		FROM
			dbo.CCT_Parameter cct
			INNER JOIN @reorder r ON r.test_param_id = cct.test_param_id
		WHERE
			cct.test_id = @test_id;
		

		UPDATE
			dbo.CCT
		SET
			number_output_params = (SELECT COUNT(*) FROM dbo.CCT_Parameter p WHERE p.test_id = cct.test_id AND param_type = 'OUTP')
		WHERE
			test_id = @test_id;

		SELECT
			@pk_id = @test_param_id,
			@operation_primary_key = 'test_param_id;' + CAST(@test_param_id AS varchar) + '|test_id;' + CAST(@test_id AS varchar);

		--Success--
		EXEC dbo.cdosys_End_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,
			@starting_tran_count = @tran_count,		
			@pk_id = @pk_id, 
			@operation_confirmed = @operation_confirmed,
			@operation_details = @operation_details,
			@operation_primary_key = @operation_primary_key,
			@message_code = @message_code;		

		IF @@trancount > @tran_count
			COMMIT TRANSACTION @proc_name;
		
	END TRY
	BEGIN CATCH 
		
		IF @@trancount > 0
		BEGIN
		
			DECLARE @stack TABLE (stack_type varchar(25) NOT NULL, proc_id int NOT NULL, nest_level int NOT NULL, stack_message nvarchar(4000) NULL);

			INSERT INTO @stack (stack_type, proc_id, nest_level, stack_message)
				SELECT stack_type, proc_id, nest_level, stack_message FROM #cdosys_Stack WHERE XACT_STATE() = -1 OR nest_level >= @@nestlevel;
				 
			IF XACT_STATE() = -1
				ROLLBACK TRANSACTION;
			ELSE IF @@trancount > @tran_count OR @save_tran = 1
				ROLLBACK TRANSACTION @proc_name;
		
			INSERT INTO #cdosys_Stack(proc_id, nest_level, stack_type, stack_message)
				SELECT proc_id, nest_level, stack_type, stack_message FROM @stack;
		END
		
		EXEC dbo.cdosys_Return_UI @proc_id = @@procid, @pk_id = @pk_id, @operation_primary_key = @operation_primary_key, @starting_tran_count = @tran_count;
				
	END CATCH
END;
GO

