CREATE PROCEDURE dbo.Deal_Test_Param_put
/*******************************************************************
* PURPOSE: Adds or updates a deal test parameter
* NOTES: 
* CREATED: 5/6/2003 by Michael Reisman
* MODIFIED 
* DATE		AUTHOR			DESCRIPTION
*-------------------------------------------------------------------
*04/28/2009	JS	Added test_param_value_ref.
*05/05/2009	JS	Added effective_date_ref.
*01/11/2010 SC  Fixing bug with page Deal_Test_Param_Edit.asp.  Added Error Handling.
*05/18/2012	SC	#3200 Changed field_name to varchar(100)
*11/20/2014	VR  #1099 Removed redundant message codes
*10/25/2018	SC	#53405 Added @copy_source_id
*02/28/2019	SC	#58183 Added unique code
*11/22/2023	SC	Updated for migration: exp id fix
*06/26/2023	AS	Updated for migration: Fix for Deal Test Parameter Expression add/edit
*10/04/2024	SC	#293897 Codes cleanup and unique by model
*08/04/2025	SC	#305456 Performance tuned
*******************************************************************/
	@m_id int,
	@deal_test_param_id int OUTPUT,
	@dtp_code varchar(100) = 'AUTO_ASSIGN',
	@deal_test_id int,
	@deal_test_param_id_parent INT = NULL, --used by parameter value histories for migration--
	@test_param_id int = NULL, --CCT_Parameter.test_param_id
	@test_param_code varchar(100) = NULL, --CCT_Parameter.param_code
	@test_param_value_type varchar(50),
	@test_param_value_control varchar(2000) = NULL,
	@test_param_value varchar(MAX) = NULL,
	@test_param_value_desc varchar(MAX) = NULL,
	@test_param_value_ref varchar(100) = NULL,
	@effective_date datetime = NULL,
	@effective_date_ref varchar(100) = NULL,
	@comments dbo.comments_small = NULL,
	@copy_source_id int = NULL, /* only used for inserts from Deal_Test_Param_copy */
	@user_id user_id,
	@silent_mode tinyint = 0,
	@operation_confirmed tinyint = 0

AS

BEGIN
	SET NOCOUNT ON;
	SET ANSI_WARNINGS ON;
	BEGIN TRY;

		DECLARE
			@proc_name sysname,
			@tran_count int,
			@save_tran bit = 0,
			@message_code varchar(50),
			@operation_details varchar(1000),
			@operation_primary_key varchar(1000),
			@pk_id int;

		SELECT 
			@proc_name = object_name(@@procid),
			@tran_count = @@trancount,
			@pk_id = @deal_test_param_id,
			@operation_primary_key = NULL;  --set below--
			
		
		IF @@NESTLEVEL = 1
		OR OBJECT_ID('tempdb..#cdosys_stack') IS NULL
		BEGIN
			DROP TABLE IF EXISTS #cdosys_stack;
			CREATE TABLE #cdosys_Stack(proc_id INT, nest_level INT, stack_type VARCHAR(25), preserve TINYINT DEFAULT(0), stack_message NVARCHAR(4000));
		END;
		
	
		IF dbo.cdosys_ContextInfo_True('NOTRAN') = 0
		BEGIN
			IF @@trancount = 0
				BEGIN TRAN @proc_name;
			ELSE
			BEGIN
				SAVE TRAN @proc_name;
				SET @save_tran = 1;
			END
		END
		--Start--
		EXEC dbo.cdosys_Start_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,			
			@starting_tran_count = @tran_count,
			@pk_id = @pk_id, 
			@row_version = NULL, 
			@operation_confirmed = @operation_confirmed;

		DECLARE
			@entity_id int,
			@starting_value varchar(MAX),
			@exp_sql VARCHAR(MAX),
			@exp_id int,
			@exp_id_old int;

		IF @test_param_value_control IS NOT NULL AND @test_param_value IS NULL
			SET @test_param_value = @test_param_value_control;

		SET @test_param_value_ref = NULLIF(@test_param_value_ref, 'VAL');
		
		IF @test_param_value_type = 'VAL'
			SET @test_param_value_ref = NULL;
		ELSE IF @test_param_value_type = 'REF'
		BEGIN
			SET @test_param_value = NULL;
			SET @test_param_value_desc = NULL;
		END

		IF @deal_test_param_id_parent IS NOT NULL
		BEGIN
			SELECT
				@deal_test_id = deal_test_id,
				@test_param_id = test_param_id
			FROM
				dbo.Deal_Test_Parameter
			WHERE
				deal_test_param_id = @deal_test_param_id_parent;
		END



		--make sure we didn't miss our field by simply needing '_UDF'
		IF @test_param_value_ref NOT LIKE '%_UDF%'
		AND NOT EXISTS (SELECT * FROM dbo.cdobiz_Data_dict WHERE field_name = @test_param_value_ref)
		AND EXISTS (SELECT * FROM dbo.cdobiz_Data_dict WHERE field_name = @test_param_value_ref + '_UDF')
			SET @test_param_value_ref = @test_param_value_ref + '_UDF';
			
		SELECT @entity_id = entity_id FROM dbo.Deal_test WHERE deal_test_id = @deal_test_id;


		IF ISNULL(@dtp_code,'AUTO_ASSIGN') = 'AUTO_ASSIGN'
		BEGIN
			SELECT @starting_value = ISNULL(test_name, '') + ' ' FROM dbo.Deal_test WHERE deal_test_id = @deal_test_id;
			SELECT @starting_value = @starting_value + test_param_name FROM dbo.CCT_Parameter WHERE test_param_id = @test_param_id;
			SELECT @dtp_code = dbo.UniqueCode(@starting_value, @deal_test_param_id, 'DTP', @m_id, NULL);
		END

		IF dbo.UniqueCodeExists(@dtp_code, @deal_test_param_id, 'DTP', @m_id, NULL) = 1
			EXEC dbo.cdosys_Return_UI @proc_id = @@procid,  @throw_error = 1,  @message_code = 'CODE_EXISTS', @s1='Portfolio Test Parameter', @s2 = @dtp_code;


		IF EXISTS (SELECT TOP 1 * FROM dbo.Deal_Test_Parameter WHERE deal_test_param_id = @deal_test_param_id)
		BEGIN
		
			IF (SELECT value_type FROM dbo.CCT_Parameter c WHERE c.test_param_id = @test_param_id) = 'E' AND ISNUMERIC(@test_param_value) = 0
			BEGIN
				SET @exp_sql = @test_param_value;

				SELECT @exp_id_old = test_param_value FROM dbo.Deal_Test_Parameter WHERE deal_test_param_id = @deal_test_param_id;

				IF @exp_id_old IS NOT NULL
					EXEC dbo.EXP_Expression_del
						@exp_id = @exp_id_old,
						@exp_target_type = 'PTP',
						@exp_target_key = @deal_test_param_id,
						@operation_confirmed = 1,
						@user_id=@user_id;

				IF @exp_sql IS NOT NULL
					EXEC dbo.EXP_Expression_put
						@m_id = @m_id,
						@exp_sql = @exp_sql,
						@entity_id = @entity_id,
						@target_type = 'PTP',
						@exp_target_key = @deal_test_param_id,
						@exp_description = NULL,
						@user_id=@user_id,
						@exp_id = @exp_id OUT;

				SET @test_param_value = @exp_id;
			END

			UPDATE dbo.Deal_Test_Parameter
			SET
				test_param_value = @test_param_value,
				test_param_value_desc = @test_param_value_desc,
				test_param_value_ref = @test_param_value_ref,
				value_type = @test_param_value_type,
				comments = @comments,
				effective_date = @effective_date,
				effective_date_ref = @effective_date_ref
			WHERE 
				deal_test_param_id = @deal_test_param_id;
	
		END
		ELSE
		BEGIN

			INSERT dbo.Deal_Test_Parameter
			(
				deal_test_id,
				test_param_id,
				test_param_value,
				test_param_value_desc,
				test_param_value_ref,
				value_type,
				effective_date,
				effective_date_ref,
				comments,
				entity_id,
				m_id,
				copy_source_id,
				dtp_code
				)
			VALUES(
				@deal_test_id,
				@test_param_id,
				@test_param_value,
				@test_param_value_desc,
				@test_param_value_ref,
				@test_param_value_type,
				@effective_date,
				@effective_date_ref,
				@comments,
				@entity_id,
				@m_id,
				@copy_source_id,
				@dtp_code
				
				);

			SELECT @deal_test_param_id = SCOPE_IDENTITY();
				
			IF (SELECT value_type FROM dbo.CCT_Parameter c WHERE c.test_param_id = @test_param_id) = 'E' AND @test_param_value IS NOT NULL AND ISNUMERIC(@test_param_value) = 0
			BEGIN
				EXEC dbo.EXP_Expression_put
					@m_id = @m_id,
					@exp_sql = @test_param_value,
					@entity_id = @entity_id,
					@target_type = 'PTP',
					@exp_target_key = @deal_test_param_id,
					@exp_description = NULL,
					@user_id = @user_id,
					@exp_id = @exp_id OUT;

				SET @test_param_value = @exp_id;

				UPDATE dbo.Deal_Test_Parameter
				SET
					test_param_value = @test_param_value
				WHERE
					deal_test_param_id = @deal_test_param_id;
			END
		END


		SELECT
			@pk_id = @deal_test_param_id,
			@operation_primary_key 
				= 'deal_test_param_id;' + CAST(@deal_test_param_id AS varchar)
				+ '|deal_test_id;' + CAST(@deal_test_id AS varchar)
				+ '|test_param_id;' + CAST(@test_param_id AS varchar);


		--Success--
		EXEC dbo.cdosys_End_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,
			@starting_tran_count = @tran_count,		
			@pk_id = @pk_id, 
			@operation_confirmed = @operation_confirmed,
			@operation_details = @operation_details,
			@operation_primary_key = @operation_primary_key,
			@message_code = @message_code;		

		IF @@trancount > @tran_count
			COMMIT TRANSACTION @proc_name;
		
	END TRY
	BEGIN CATCH 
		
		IF @@trancount > 0
		BEGIN
		
			DECLARE @stack TABLE (stack_type varchar(25) NOT NULL, proc_id int NOT NULL, nest_level int NOT NULL, stack_message nvarchar(4000) NULL);

			INSERT INTO @stack (stack_type, proc_id, nest_level, stack_message)
				SELECT stack_type, proc_id, nest_level, stack_message FROM #cdosys_Stack WHERE XACT_STATE() = -1 OR nest_level >= @@nestlevel;
				 
