	@psv_id int = NULL,
	@force_float tinyint = 0,
	@user_id [user_id] = NULL,
	@operation_confirmed tinyint = 1,
	@silent_mode tinyint = 1	
)
AS
BEGIN


	SET NOCOUNT ON;
	BEGIN TRY;

		DECLARE
			@proc_name sysname,
			@tran_count int,
			@save_tran bit = 0,
			@message_code varchar(50),
			@operation_details varchar(1000),
			@operation_primary_key varchar(1000),
			@pk_id int;

		SELECT 
			@proc_name = object_name(@@procid),
			@tran_count = @@trancount,
			@pk_id = NULL,
			@operation_primary_key = NULL;
			
		
		IF @@NESTLEVEL = 1
		OR OBJECT_ID('tempdb..#cdosys_stack') IS NULL
		BEGIN
			DROP TABLE IF EXISTS #cdosys_stack;
			CREATE TABLE #cdosys_Stack(proc_id INT, nest_level INT, stack_type VARCHAR(25), preserve TINYINT DEFAULT(0), stack_message NVARCHAR(4000));
		END;

		 IF ISNULL(dbo.ConfigValue('PS_GEN_TRAN', NULL),0) = 1 
		AND dbo.cdosys_ContextInfo_True('NOTRAN') = 0
		BEGIN
			IF @@trancount = 0
				BEGIN TRAN @proc_name;
			ELSE
			BEGIN
				SAVE TRAN @proc_name;
				SET @save_tran = 1;
			END
		END



		--Start--
		EXEC dbo.cdosys_Start_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,			
			@starting_tran_count = @tran_count,
			@pk_id = @pk_id, 
			@row_version = NULL, 
			@operation_confirmed = @operation_confirmed;

		DECLARE @custom_fields TABLE(field_id int NOT NULL PRIMARY KEY, aggregation_level varchar(25) NULL);
	
		DECLARE 
			@insert_command varchar(MAX),
			@alter_comand varchar(MAX),
			@update_command varchar(MAX),
			@field_list varchar(4000),
			@aggregation_level varchar(25),
			@field_id int,
			@entity_id int,
			@ps_id int;

		--Get entity id for the current portfolio snapshot--
		SELECT @ps_id = ps_id FROM dbo.PS_Version WHERE psv_id = @psv_id;
		SELECT @entity_id = entity_id FROM dbo.PS_Portfolio_Snapshot WHERE ps_id = @ps_id;
		
		--get custom fields--
		INSERT INTO @custom_fields 
			SELECT 	record_string, aggregation_level 
			FROM 	
				dbo.tf_split2(@fields, ',') rec
				INNER JOIN dbo.cdobiz_Data_dict dd ON rec.record_string = dd.field_id
			WHERE
				field_type = @field_type;

		--Insert--	
		IF @command_mode = 'INSERT'
		BEGIN
		
			SELECT 
				@field_list = ISNULL(@field_list, '') + '[' + field_name + ']'',' 
			FROM 
				dbo.cdobiz_Data_Dict dd
				INNER JOIN @custom_fields cf ON dd.field_id = cf.field_id;

			SELECT @field_list = REPLACE(@field_list, 'issue_id', 'PS_Issue.issue_id');

			--Remove trailing comma--
			IF LEN(@field_list) > 0
				SET @field_list = SUBSTRING(@field_list,1, LEN(@field_list)-1);

			IF EXISTS(SELECT TOP 1 * FROM @custom_fields WHERE aggregation_level = 'ITEM')
				SET @aggregation_level = 'ITEM';

			SET @insert_command 
				= 'INSERT INTO ' + @table_name + '(' + REPLACE(REPLACE(ISNULL(@extra_fields, '') + ISNULL(@field_list, ''), 'PS_Issue.', ''), '=NULL', '') + ')'
				+ ' SELECT ' + ISNULL(@extra_fields, '') + @field_list 
				+	CASE @aggregation_level 
						WHEN 'ITEM' THEN ' FROM dbo.Entity CROSS JOIN dbo.PS_Issue INNER JOIN PS_Item ON PS_Issue.ps_issue_id = PS_Item.ps_issue_id LEFT OUTER JOIN dbo.PS_Issue_Rating pir ON PS_Issue.ps_issue_id = pir.ps_issue_id  '
						ELSE ' FROM dbo.Entity CROSS JOIN dbo.PS_Issue LEFT OUTER JOIN dbo.PS_Issue_Rating pir ON PS_Issue.ps_issue_id = pir.ps_issue_id  '
					END  
				+	' WHERE Entity.entity_id =  ' + CONVERT(varchar, @entity_id) + ' and PS_Issue.ps_id =  ' + CONVERT(varchar, @ps_id);

			SET @insert_command = REPLACE(@insert_command, 'issuer_id', 'PS_ISSUE.issuer_id')
			EXEC dbo.cdosys_Stack_Put @proc_id = @@procid, @nest_level = @@nestlevel, @stack_type = 'DYNAMICSQL', @stack_message = @insert_command;
			EXEC(@insert_command);
		END
		ELSE
		BEGIN
			SET @field_id = (SELECT MIN(field_id) FROM @custom_fields);

			WHILE @field_id IS NOT NULL
			BEGIN
				--modify and update table with custom fields--
				SELECT 	
					@alter_comand 
						= 'ALTER TABLE ' + @table_name 
						+ '  ADD [' + field_name  + ']'
						+	CASE data_type 	
								WHEN 'NUMERIC'  THEN ' float NULL' 
								WHEN 'TEXT'     THEN ' varchar(255) NULL' 
								WHEN 'CURRENCY' THEN CASE WHEN @force_float = 1 THEN ' float NULL'  ELSE ' money NULL ' END
								WHEN 'BOOLEAN'  THEN ' tinyint NULL' 
								WHEN 'DATE'     THEN ' datetime NULL' 
								WHEN 'PERCENT'  THEN ' float NULL' 
								WHEN 'TABLE'    THEN ' varchar(MAX)' 
								ELSE ' varchar(255) NULL' 
							END,
					@update_command 
						= 'UPDATE ' + @table_name 
						+ '  SET [' + field_name +  ']'+ ' = CAST(RTRIM(field_value) AS ' 
						+	CASE data_type 	
								WHEN 'NUMERIC' 	THEN 'float' 
								WHEN 'TEXT' 	THEN 'varchar(255)' 
								WHEN 'CURRENCY' THEN CASE WHEN @force_float = 1 THEN 'float' ELSE 'money' END
								WHEN 'BOOLEAN' 	THEN 'tinyint' 
								WHEN 'DATE' 	THEN 'datetime' 
								WHEN 'PERCENT' 	THEN 'float' 
								WHEN 'TABLE' 	THEN 'varchar(MAX)'
								ELSE 'varchar(255)' 
							END + ') FROM ' 
						+ @table_name + ' psc INNER JOIN ' 
						+	CASE aggregation_level 
								 WHEN 'ITEM' THEN 'dbo.PS_Item_Custom ON psc.ps_item_id = PS_Item_Custom.ps_item_id WHERE PS_Item_Custom.field_id = '
								 WHEN 'ENT'  THEN 'dbo.PS_Custom ON ' + CAST(@ps_ID AS varchar) + ' = PS_Custom.ps_id WHERE PS_Custom.field_id = '
								 WHEN 'AGGR' THEN 'dbo.PS_Aggregate ON ' + CAST(@psv_ID AS varchar) + '  = PS_Aggregate.psv_id WHERE PS_Aggregate.field_id = '
								ELSE 'dbo.PS_Issue_Custom ON psc.ps_issue_id = PS_Issue_Custom.ps_issue_id WHERE PS_Issue_Custom.field_id = ' 
							END 
						+ CAST(@field_id AS varchar)
				FROM 
					dbo.cdobiz_Data_Dict 
				WHERE 
					field_id = @field_id;

				
				IF @command_mode = 'FULL' 
				OR @command_mode = 'ALTER'
				BEGIN
					EXEC dbo.cdosys_Stack_Put @proc_id = @@procid, @nest_level = @@nestlevel, @stack_type = 'DYNAMICSQL', @stack_message = @alter_comand;
					EXEC(@alter_comand);
				END

				IF @command_mode = 'FULL' 
				OR @command_mode = 'UPDATE'
				BEGIN
					EXEC dbo.cdosys_Stack_Put @proc_id = @@procid, @nest_level = @@nestlevel, @stack_type = 'DYNAMICSQL', @stack_message = @update_command;
					EXEC(@update_command);
				END
				
				SET @field_id = (SELECT MIN(field_id) FROM @custom_fields WHERE field_id > @field_id);
			
			END --@field_id IS NOT NULL--
		END --@command_mode <> 'INSERT'--
		

		--Success--
		EXEC dbo.cdosys_End_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,
			@starting_tran_count = @tran_count,		
			@pk_id = @pk_id, 
			@operation_confirmed = @operation_confirmed,
			@operation_details = @operation_details,
			@operation_primary_key = @operation_primary_key,
			@message_code = @message_code;		

		IF @@trancount > @tran_count
			COMMIT TRANSACTION @proc_name;
		
	END TRY
	BEGIN CATCH 
		
		IF @@trancount > 0
		BEGIN
		
			DECLARE @stack TABLE (stack_type varchar(25) NOT NULL, proc_id int NOT NULL, nest_level int NOT NULL, stack_message nvarchar(4000) NULL);

			INSERT INTO @stack (stack_type, proc_id, nest_level, stack_message)
				SELECT stack_type, proc_id, nest_level, stack_message FROM #cdosys_Stack WHERE XACT_STATE() = -1 OR nest_level >= @@nestlevel;
				 
			IF XACT_STATE() = -1
				ROLLBACK TRANSACTION;
			ELSE IF @@trancount > @tran_count OR @save_tran = 1
