-- <% MACRO\HEADER %>
CREATE PROCEDURE [dbo].[PS_Custom_process]
/*******************************************************************
* PROCEDURE: PS_Custom_Process
* PURPOSE: 	Generates PS custom table.
* NOTES: 
* CREATED: 	9/8/2003 by Inga Turgil
* MODIFIED 
* DATE		AUTHOR		DESCRIPTION
*-------------------------------------------------------------------
* 11/02/2006	VR	Changed data type smalldatetime to datetime to comply with maturity dates that 
*					are greater than the smalldatetime type will allow
* 02/20/2009	CC	Add entity level UDF and data_type = 'TABLE'
* 08/05/2009	SC	Added new error handling
* 08/08/2012	SC	Changed ps_id to psv_id
* 10/26/2012	SC	#3444 Fix for latest version of compliance
* 08/28/2013	SC	#3910 Increased table size to 8000
* 07/09/2014	SC	#5330 Increased table size to MAX
* 07/23/2015	SC	#4469 Added @force_float
* 02/15/2016	SC	#14623 Fix for layout fields
* 03/25/2021	TK	#163373. #175462. Fixed dynamic SQL when PS Layout includes columns from PS_Issue_Rating
* 08/20/2021	TK	#200168. #202783. Fixed/added column list when @command_mode = INSERT  
* 03/26/2026	HK	Field names starting with integers must be wrapped in square brackets to comply with SQL Server syntax rules.
*******************************************************************/
(
	@fields varchar(MAX),
	@table_name varchar(255) = '#PS_Custom',
	@field_type dbo.lookup_code = 'UDF',
	@command_mode varchar(10) = 'FULL', --ALTER, UPDATE, FULL, INSERT--
	@extra_fields varchar(MAX) = NULL,
	@psv_id int = NULL,
	@force_float tinyint = 0,
	@user_id [user_id] = NULL,
	@operation_confirmed tinyint = 1,
	@silent_mode tinyint = 1	
)
AS
BEGIN


	SET NOCOUNT ON;
	BEGIN TRY;

		DECLARE
			@proc_name sysname,
			@tran_count int,
			@save_tran bit = 0,
			@message_code varchar(50),
			@operation_details varchar(1000),
			@operation_primary_key varchar(1000),
			@pk_id int;

		SELECT 
			@proc_name = object_name(@@procid),
			@tran_count = @@trancount,
			@pk_id = NULL,
			@operation_primary_key = NULL;
			
		
		IF @@NESTLEVEL = 1
		OR OBJECT_ID('tempdb..#cdosys_stack') IS NULL
		BEGIN
			DROP TABLE IF EXISTS #cdosys_stack;
			CREATE TABLE #cdosys_Stack(proc_id INT, nest_level INT, stack_type VARCHAR(25), preserve TINYINT DEFAULT(0), stack_message NVARCHAR(4000));
		END;

		 IF ISNULL(dbo.ConfigValue('PS_GEN_TRAN', NULL),0) = 1 
		AND dbo.cdosys_ContextInfo_True('NOTRAN') = 0
		BEGIN
			IF @@trancount = 0
				BEGIN TRAN @proc_name;
			ELSE
			BEGIN
				SAVE TRAN @proc_name;
				SET @save_tran = 1;
			END
		END



		--Start--
		EXEC dbo.cdosys_Start_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,			
			@starting_tran_count = @tran_count,
			@pk_id = @pk_id, 
			@row_version = NULL, 
			@operation_confirmed = @operation_confirmed;

		DECLARE @custom_fields TABLE(field_id int NOT NULL PRIMARY KEY, aggregation_level varchar(25) NULL);
	
		DECLARE 
			@insert_command varchar(MAX),
			@alter_comand varchar(MAX),
			@update_command varchar(MAX),
			@field_list varchar(4000),
			@aggregation_level varchar(25),
			@field_id int,
			@entity_id int,
			@ps_id int;

		--Get entity id for the current portfolio snapshot--
		SELECT @ps_id = ps_id FROM dbo.PS_Version WHERE psv_id = @psv_id;
		SELECT @entity_id = entity_id FROM dbo.PS_Portfolio_Snapshot WHERE ps_id = @ps_id;
		
		--get custom fields--
		INSERT INTO @custom_fields 
			SELECT 	record_string, aggregation_level 
			FROM 	
				dbo.tf_split2(@fields, ',') rec
				INNER JOIN dbo.cdobiz_Data_dict dd ON rec.record_string = dd.field_id
			WHERE
				field_type = @field_type;

		--Insert--	
		IF @command_mode = 'INSERT'
		BEGIN
		
			SELECT 
				@field_list = ISNULL(@field_list, '') + 
					CASE WHEN field_name LIKE '[0-9]%' THEN QUOTENAME(field_name) + ',' ELSE field_name + ',' END
			FROM 
				dbo.cdobiz_Data_Dict dd
				INNER JOIN @custom_fields cf ON dd.field_id = cf.field_id;

			SELECT @field_list = REPLACE(@field_list, 'issue_id', 'PS_Issue.issue_id');

			--Remove trailing comma--
			IF LEN(@field_list) > 0
				SET @field_list = SUBSTRING(@field_list,1, LEN(@field_list)-1);

			IF EXISTS(SELECT TOP 1 * FROM @custom_fields WHERE aggregation_level = 'ITEM')
				SET @aggregation_level = 'ITEM';

			SET @insert_command 
				= 'INSERT INTO ' + @table_name + '(' + REPLACE(REPLACE(ISNULL(@extra_fields, '') + ISNULL(@field_list, ''), 'PS_Issue.', ''), '=NULL', '') + ')'
				+ ' SELECT ' + ISNULL(@extra_fields, '') + @field_list 
				+	CASE @aggregation_level 
						WHEN 'ITEM' THEN ' FROM dbo.Entity CROSS JOIN dbo.PS_Issue INNER JOIN PS_Item ON PS_Issue.ps_issue_id = PS_Item.ps_issue_id LEFT OUTER JOIN dbo.PS_Issue_Rating pir ON PS_Issue.ps_issue_id = pir.ps_issue_id  '
						ELSE ' FROM dbo.Entity CROSS JOIN dbo.PS_Issue LEFT OUTER JOIN dbo.PS_Issue_Rating pir ON PS_Issue.ps_issue_id = pir.ps_issue_id  '
					END  
				+	' WHERE Entity.entity_id =  ' + CONVERT(varchar, @entity_id) + ' and PS_Issue.ps_id =  ' + CONVERT(varchar, @ps_id);

			SET @insert_command = REPLACE(@insert_command, 'issuer_id', 'PS_ISSUE.issuer_id')
			EXEC dbo.cdosys_Stack_Put @proc_id = @@procid, @nest_level = @@nestlevel, @stack_type = 'DYNAMICSQL', @stack_message = @insert_command;
			EXEC(@insert_command);
		END
		ELSE
		BEGIN
			SET @field_id = (SELECT MIN(field_id) FROM @custom_fields);

			WHILE @field_id IS NOT NULL
			BEGIN
				--modify and update table with custom fields--
				SELECT 	
					@alter_comand 
						= 'ALTER TABLE ' + @table_name 
						+ '  ADD [' + field_name  + ']'
						+	CASE data_type 	
								WHEN 'NUMERIC'  THEN ' float NULL' 
								WHEN 'TEXT'     THEN ' varchar(255) NULL' 
								WHEN 'CURRENCY' THEN CASE WHEN @force_float = 1 THEN ' float NULL'  ELSE ' money NULL ' END
								WHEN 'BOOLEAN'  THEN ' tinyint NULL' 
								WHEN 'DATE'     THEN ' datetime NULL' 
								WHEN 'PERCENT'  THEN ' float NULL' 
								WHEN 'TABLE'    THEN ' varchar(MAX)' 
								ELSE ' varchar(255) NULL' 
							END,
					@update_command 
						= 'UPDATE ' + @table_name 
						+ '  SET [' + field_name +  ']'+ ' = CAST(RTRIM(field_value) AS ' 
						+	CASE data_type 	
								WHEN 'NUMERIC' 	THEN 'float' 
								WHEN 'TEXT' 	THEN 'varchar(255)' 
								WHEN 'CURRENCY' THEN CASE WHEN @force_float = 1 THEN 'float' ELSE 'money' END
								WHEN 'BOOLEAN' 	THEN 'tinyint' 
								WHEN 'DATE' 	THEN 'datetime' 
								WHEN 'PERCENT' 	THEN 'float' 
								WHEN 'TABLE' 	THEN 'varchar(MAX)'
								ELSE 'varchar(255)' 
							END + ') FROM ' 
						+ @table_name + ' psc INNER JOIN ' 
						+	CASE aggregation_level 
								 WHEN 'ITEM' THEN 'dbo.PS_Item_Custom ON psc.ps_item_id = PS_Item_Custom.ps_item_id WHERE PS_Item_Custom.field_id = '
								 WHEN 'ENT'  THEN 'dbo.PS_Custom ON ' + CAST(@ps_ID AS varchar) + ' = PS_Custom.ps_id WHERE PS_Custom.field_id = '
								 WHEN 'AGGR' THEN 'dbo.PS_Aggregate ON ' + CAST(@psv_ID AS varchar) + '  = PS_Aggregate.psv_id WHERE PS_Aggregate.field_id = '
								ELSE 'dbo.PS_Issue_Custom ON psc.ps_issue_id = PS_Issue_Custom.ps_issue_id WHERE PS_Issue_Custom.field_id = ' 
							END 
						+ CAST(@field_id AS varchar)
				FROM 
					dbo.cdobiz_Data_Dict 
				WHERE 
					field_id = @field_id;

				
				IF @command_mode = 'FULL' 
				OR @command_mode = 'ALTER'
				BEGIN
					EXEC dbo.cdosys_Stack_Put @proc_id = @@procid, @nest_level = @@nestlevel, @stack_type = 'DYNAMICSQL', @stack_message = @alter_comand;
					EXEC(@alter_comand);
				END

				IF @command_mode = 'FULL' 
				OR @command_mode = 'UPDATE'
				BEGIN
					EXEC dbo.cdosys_Stack_Put @proc_id = @@procid, @nest_level = @@nestlevel, @stack_type = 'DYNAMICSQL', @stack_message = @update_command;
					EXEC(@update_command);
				END
				
				SET @field_id = (SELECT MIN(field_id) FROM @custom_fields WHERE field_id > @field_id);
			
			END --@field_id IS NOT NULL--
		END --@command_mode <> 'INSERT'--
		

		--Success--
		EXEC dbo.cdosys_End_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,
			@starting_tran_count = @tran_count,		
			@pk_id = @pk_id, 
			@operation_confirmed = @operation_confirmed,
			@operation_details = @operation_details,
			@operation_primary_key = @operation_primary_key,
			@message_code = @message_code;		

		IF @@trancount > @tran_count
			COMMIT TRANSACTION @proc_name;
		
	END TRY
	BEGIN CATCH 
		
		IF @@trancount > 0
		BEGIN
		
			DECLARE @stack TABLE (stack_type varchar(25) NOT NULL, proc_id int NOT NULL, nest_level int NOT NULL, stack_message nvarchar(4000) NULL);

			INSERT INTO @stack (stack_type, proc_id, nest_level, stack_message)
				SELECT stack_type, proc_id, nest_level, stack_message FROM #cdosys_Stack WHERE XACT_STATE() = -1 OR nest_level >= @@nestlevel;
				 
			IF XACT_STATE() = -1
				ROLLBACK TR

-- <% MACRO\HEADER %>
CREATE FUNCTION dbo.PS_CB_ParameterValue
/*******************************************************************
* PURPOSE:  Returns parameter value but used ONLY for calculation blocks. 
* NOTES: 
* CREATED: 04/28/2009 by John Shkolnik
* MODIFIED 
* DATE		AUTHOR			DESCRIPTION
*-------------------------------------------------------------------
*05/12/2009		SC	Fixed REF variables in/out conditions
*01/25/2010		SC	Added raw value flag so we can get the uninterpreted version for value_type = 'E'
*03/27/2015		SC	#5772 Added call to PS_AggrFieldValue
*10/02/2016		SC	#26073 Codes/fields to varchar(100)
*11/29/2018		SC	#53405 Added logic for models
*04/28/2024		SC	#415033 Performance improvement
*10/04/2024		SC	#293897 Codes cleanup and unique by model
*07/29/2025		SC	#305462 Performance tune
*******************************************************************/
(
	@psv_id int, 
	@dcb_id int, 
	@param_code varchar(100),  --formerly @sql_variable_name--
	@default_value varchar(MAX) = NULL,
	@raw_value tinyint = 0
)
RETURNS varchar(MAX)
AS
BEGIN

	DECLARE
		@param_value varchar(MAX),
		@param_value_ref varchar(MAX),
		@ps_id int,
		@m_id int,
		@param_value_type char(4),
		@param_type lookup_code,
		@entity_id int,
		@source_entities varchar(500),
		@is_consolidated_entity bit;

	DECLARE @account_list TABLE (account_id int, entity_id int);
	DECLARE @debt_notes TABLE (note_code varchar(200), entity_id int);
	DECLARE @source_entity_table TABLE (source_entity_id int, deal_name nvarchar(120));

	SELECT
		@ps_id = ps.ps_id,
		@m_id = ps.m_id,
		@entity_id = ps.entity_id
	FROM
		dbo.PS_Portfolio_Snapshot ps
		INNER JOIN dbo.PS_Version psv ON ps.ps_id = psv.ps_id
	WHERE
		 psv_id = @psv_id;


	SET @is_consolidated_entity = dbo.IsConsolidatedEntity(@entity_id);
	SELECT TOP 1 @source_entities = source_entities FROM dbo.PS_Issue WHERE ps_id = @ps_id;

	INSERT INTO @source_entity_table (source_entity_id, deal_name)
		SELECT source_entity_id, deal_name FROM dbo.tf_PS_Source_Entity(@source_entities);

	WITH
	 dcbp_view AS ( /* code is from DC_CB_Parameter_view */
		SELECT
			cbp.dcb_param_id, 
			param_value_type = cbp.value_type,
			cbp.param_value,
			cbp.param_value_ref,
			cp.param_type, --input/output--
			cp.value_type
		FROM 
			dbo.DC_Calculation_Block_Parameter cbp 
			INNER JOIN dbo.CCT_Parameter cp ON cbp.param_id = cp.test_param_id
		WHERE
			cbp.dcb_id = @dcb_id
		AND cp.SQL_variable_name = @param_code
		AND cbp.m_id = @m_id
	)
	SELECT
		@param_value_ref = pv.param_value_ref,
		@param_type = pv.param_type,
		@param_value = CASE WHEN pv.value_type = 'E' AND @raw_value = 0 THEN dbo.ExpDesc(pv.param_value, 'SQL') ELSE pv.param_value END,
		@param_value_type = pv.param_value_type
	FROM 
		dcbp_view pv;

	IF @is_consolidated_entity = 'True'
	BEGIN
		IF @param_code = '@cash_accounts' OR @param_code = '@account_list'
		BEGIN
			INSERT @account_list(account_id, entity_id)
				SELECT
					CAST(b.record_string AS int),
					a.entity_id
				FROM
					dbo.tf_split2(@param_value, ',') b
					INNER JOIN dbo.Account a ON a.account_id = CAST(b.record_string AS int);

			DELETE a
			FROM
				@account_list a
				LEFT OUTER JOIN @source_entity_table ps ON a.entity_id = ps.source_entity_id
			WHERE
				ps.source_entity_id IS NULL;

			SET @param_value = NULL;
			SELECT @param_value = COALESCE(@param_value + ',', '') + CAST(account_id AS NVARCHAR(MAX)) FROM @account_list;
		END
		ELSE IF @param_code = '@debt_notes'
		BEGIN
			INSERT @debt_notes(note_code, entity_id)
				SELECT
					CAST(b.record_string AS NVARCHAR(200)),
					e.entity_id
				FROM
					dbo.tf_split2(@param_value, ',') b
					JOIN dbo.Entity_Note e ON e.note_code + '_' + ISNULL(dbo.EntityCode(e.entity_id), '') = CAST(b.record_string AS NVARCHAR(200));

			DELETE d
			FROM
				@debt_notes d
				LEFT OUTER JOIN @source_entity_table ps ON d.entity_id = ps.source_entity_id
			WHERE
				ps.source_entity_id IS NULL;

			SET @param_value = NULL;
			SELECT @param_value = COALESCE(@param_value + ',', '') + CAST(note_code AS NVARCHAR(200)) FROM @debt_notes;
		END
	END

	IF @param_value_type = 'REF'
	BEGIN
		IF @param_type = 'INP'
			SELECT @param_value = dbo.PS_AggrFieldValue(@psv_id, dbo.EXPFieldID(@param_value_ref));
		ELSE --	@param_type = 'OUTP'--
			SELECT @param_value = @param_value_ref;
	END
	
	RETURN ISNULL(NULLIF(LTRIM(@param_value), ''), @default_value);

END
GO

able TABLE (variable_name varchar(255), variable_value varchar(255));
		
		IF @parameters IS NOT NULL
			INSERT INTO @params_table(variable_name, variable_value)
				SELECT 
					LTRIM(RTRIM(dbo.StringToken(record_string, '=', 1))),
					LTRIM(RTRIM(dbo.StringToken(record_string, '=', 2))) 
				FROM 
					dbo.tf_split2(@parameters, ',');
				
		SELECT
			@ps_id = psv.ps_id,
			@ts_id = psv.ts_id,
			@as_of_date = ps.as_of_date,
			@entity_id = ps.entity_id,
			@m_id = ps.m_id
		FROM 
			dbo.PS_Version psv
			INNER JOIN dbo.PS_Portfolio_Snapshot ps ON ps.ps_id = psv.ps_id
		WHERE 
			psv.psv_id = @psv_id;
		

		--we have to regen the output to get all the good debug info--
		 IF ISNULL(dbo.ConfigValue('PS_GEN_DEBUG', @entity_id),0) = 1 
		AND	@run_mode = 'DISP'
			SET @run_mode = 'FULL';
			
		SELECT 
			@dynamic_proc_name = CASE c.template_type WHEN 'CUST' THEN '#custom_proc' + LTRIM(STR(@dcb_id)) ELSE c.sp_name END,
			@template_type 	= c.template_type,
			@calc_id = c.test_id
		FROM 
			dbo.DC_Calculation_Block t
			INNER JOIN dbo.CCT c ON t.calc_id = c.test_id
		WHERE 
			t.dcb_id = @dcb_id;


		SELECT
			@portfolio_name = deal_name,
			@entity_id = entity_id,
			@dcg_id = dcg_id, 
			@dcb_description = dcb_description,
			@dcg_description = dcg_description
		FROM 
			dbo.DC_Calculation_Block_view
		WHERE
			dcb_id = @dcb_id
		AND entity_id = @entity_id
		AND m_id = @m_id;

		EXEC dbo.cdosys_Stack_Put @proc_id = @@procid, @nest_level = @@nestlevel, @stack_type = 'STACK', @stack_message = @dcb_description;

		SELECT @pps_id = pps_id FROM dbo.PP_Payment_Step WHERE dcb_id = @dcb_id AND m_id = @m_id;
		IF @pps_id IS NOT NULL
			SELECT @pss_id = pss_id FROM dbo.PS_PP_Payment_Step WHERE psv_id = @psv_id AND pps_id = @pps_id;
							
		--if we are saving, don't display any results--
		IF @run_mode = 'SAVE'
			SET @recordset_code = 'NONE';
			
		BEGIN TRY
			IF  @template_type = 'CUST' 
			AND @calc_id IS NOT NULL
				EXEC dbo.PS_CB_Custom_SP_create @dcb_id = @dcb_id, @custom_proc_name = @dynamic_proc_name, @recordset_code = @recordset_code;
					

  			SET @sql_command = 'EXEC ' + @dynamic_proc_name +
				+ '  @psv_id = ' + RTRIM(LTRIM(STR(@psv_id)))
				+ ', @dcb_id = ' + RTRIM(LTRIM(STR(@dcb_id)));

			IF @run_mode IS NOT NULL
				SET @sql_command = @sql_command + ',@run_mode=''' + @run_mode + '''';

			IF @recordset_code IS NOT NULL
				SET @sql_command = @sql_command + ',@recordset_code='''+ @recordset_code + '''';

			IF @layout_code IS NOT NULL
				SET @sql_command = @sql_command + ',@layout_code='''+ @layout_code + '''';

			-- To check if the dynamic_proc_name has use_display_name as input parameter or not --
			IF @use_display_name IS NOT NULL AND EXISTS (
			SELECT name,parameter_names  
			FROM (
				SELECT o.[name],  STRING_AGG(p.name, ', ') AS parameter_names
				FROM sys.parameters p
				JOIN sys.objects o ON p.object_id = o.object_id
				WHERE o.type = 'P'
				GROUP BY o.[name]
			) sprocs 
			WHERE COALESCE(LEFT(@dynamic_proc_name, NULLIF(CHARINDEX('@', @dynamic_proc_name), 0) - 1), @dynamic_proc_name)  LIKE '%' + name +'%' 
				AND '@use_display_name' IN(SELECT TRIM(value) FROM STRING_SPLIT(sprocs.parameter_names, ','))
			)
			BEGIN
				SET @sql_command = @sql_command + ',@use_display_name='''+ CAST(@use_display_name AS varchar) + '''';
			END

			--Stored procedure parameters--
			DECLARE param_cursor CURSOR LOCAL READ_ONLY FORWARD_ONLY
			FOR 
				SELECT distinct
					p.param_order,
					p.dcb_param_id,
					p.SQL_variable_name,
					p.value_type,
					p.data_type,
					p.param_value_type
				FROM dbo.DC_CB_Parameter_view p --this view can produce duplicate rows so leave distinct for select--
				WHERE p.dcb_id = @dcb_id
				  AND p.m_id = @m_id
				ORDER BY p.param_order;

			OPEN param_cursor;
			FETCH NEXT FROM param_cursor INTO @param_order, @dcb_param_id, @var_name, @value_type, @data_type, @param_value_type;
			WHILE @@fetch_status = 0
			BEGIN
				SET @param_value = dbo.PS_CB_ParameterValue(@psv_id, @dcb_id, @var_name, NULL,0);
				SET @len = 0;
				SET @ct = 1;
				SET @pos = 0;
				SET @l1= 0;
				SET @begin= 0;
				SET @opos = 0;
				SET @cpos = 0;

				IF @var_name = '@formula'  
					AND (CHARINDEX('CONVERT(float, DATEDIFF (', @param_value) = 0 
					AND CHARINDEX('CONVERT(float, DATEDIFF(', @param_value) = 0)
					AND CHARINDEX('CAST(DATEDIFF', @param_value) = 0
				BEGIN 
					SELECT @pos =  CHARINDEX('DATEDIFF (', @param_value);
					SET @l1 = len('DATEDIFF (');

					IF @pos = 0 
					BEGIN
						SELECT @pos =  CHARINDEX('DATEDIFF(', @param_value);
						SET @l1 = len('DATEDIFF(');
					END
					
					IF @pos > 0
					BEGIN
						SET @begin = @pos;

						SELECT @opos = CHARINDEX('(', @param_value, @begin + @l1); 
						SELECT @cpos = CHARINDEX(')', @param_value, @begin);

						IF (@opos < @cpos AND @opos > 0) 
							SET @ct = @ct + 1; 
						ELSE 
							SET @ct = @ct - 1;

						IF @ct = 0	
							SET @len = @cpos - @pos + 1; 
						ELSE 
							SET @begin = CASE WHEN (@opos < @cpos AND @opos > 0) THEN @opos + 1 ELSE @cpos + 1 END;

						WHILE (@ct <> 0 AND (@opos <> 0 OR @cpos <> 0))
						BEGIN
							SET @opos = NULL;
							SET @cpos = NULL;

							SELECT @opos = CHARINDEX('(', @param_value, @begin); 
							SELECT @cpos = CHARINDEX(')', @param_value, @begin); 

							IF (@opos < @cpos AND @opos > 0) 
								SET @ct = @ct + 1; 
							ELSE 
								SET @ct = @ct - 1;
							
							IF @ct = 0	
								SET @len = @cpos - @pos + 1; 
							ELSE 
								SET @begin = CASE WHEN (@opos < @cpos AND @opos > 0) THEN @opos + 1 ELSE @cpos + 1 END;
						END

						IF @len > 0
						SELECT @param_value = REPLACE(@param_value, substring(@param_value, @pos, @len), 'CAST(' + substring(@param_value, @pos, @len) + ' AS DECIMAL(16,10))');							
					END
				END
				IF NOT EXISTS (SELECT * FROM @params_table WHERE variable_name = LTRIM(RTRIM(@var_name)))
				BEGIN
					SET @sql_command 
						= @sql_command + ', ' 
						+ @var_name + ' = ' 
						+	CASE 
								WHEN ISNULL(@param_value, '') = '' THEN 'DEFAULT'
								WHEN @data_type IN ('N', 'M') AND @value_type NOT IN ('E', 'M') AND @param_value_type <> 'REF' THEN @param_value
								ELSE dbo.QuoteString(@param_value) 
							END;
				END	
				FETCH NEXT FROM param_cursor INTO @param_order, @dcb_param_id, @var_name, @value_type, @data_type, @param_value_type;
			END
			CLOSE param_cursor;
			DEALLOCATE param_cursor;

			IF @parameters IS NOT NULL
				SET @sql_command = @sql_command + ',' + @parameters;
				
			EXEC dbo.cdosys_Stack_Put @proc_id = @@procid, @nest_level = @@nestlevel, @stack_type = 'DYNAMICSQL', @stack_message = @sql_command;
			
			 IF @pss_id IS NOT NULL
			AND @sql_command NOT LIKE '%@pp_id%'
				SET @sql_command = 'EXEC dbo.PS_PP_Payment_Step_run @pss_id =' + STR(@pss_id);
			ELSE
			BEGIN
				--Display Test Parameter--
				IF  @run_mode IN ('FULL', 'DISP') 
				AND @recordset_code IN('ALL', 'PARAMS')
				AND dbo.PS_CB_IsFormula(@dcb_id) = 0 --formulas display limited/special details in PS_CB_Formula--
					EXEC dbo.PS_CB_Parameter_list @dcb_id = @dcb_id, @psv_id = @psv_id, @parameters = @parameters;
			END

      --PRINT @sql_command;  

			EXEC (@sql_command);
		END TRY
		BEGIN CATCH
		
			SELECT @format_details = '';
			--this will allow calculation web pages to display the error results in a table--
			IF @@nestlevel = @nest_level_display
				SELECT * FROM dbo.tf_Message_Code(ERROR_MESSAGE());
			ELSE
			BEGIN
				SET @operation_details = char(10) + char(10) + ERROR_MESSAGE();
				
				SELECT @stack_message = NULL;
				SELECT @stack_message = stack_message FROM #cdosys_stack WHERE proc_id = OBJECT_ID('PS_Field_update') AND stack_type = 'FIELDNAME';
				SET @field_name = ISNULL(@stack_message, 'N/A');
				
				EXEC dbo.cdosys_Format_Operation_Details
					@message_code = 'CB_RUN_FAILED',
					@s1 = @portfolio_name, 
					@i2 = @entity_id,
					@s3 = @dcg_description,
					@i4 = @dcg_id,
					@s5 = @dcb_description,
					@i6 = @dcb_id,
					@s7 = @field_name,
					@result = @format_details OUTPUT;
				
				SELECT @stack_message = NULL;
				SELECT @stack_message = stack_message FROM #cdosys_stack WHERE stack_type = 'CB_RUN_FAILED';

				IF @stack_message IS NOT NULL AND @@nestlevel = 4 --calling from Calculations page
					SELECT @format_details = '<br/><br/>' + @format_details;
				ELSE IF @@nestlevel = 5 --calling from ps_generate
				BEGIN
					SELECT @format_details = '

' + @format_details;
				END
				SELECT @format_details = @format_details + ' -> ' + @operation_details;
				EXEC dbo.cdosys_Stack_Put @proc_id = @@procid, @nest_level = @@nestlevel, @stack_type = 'CB_RUN_FAILED', @stack_message = @format_details, @preserve=1;
			END
		END CATCH

		-- Cleanup - delete te
